// packages/wb-core/src/index.js

import WBCOptions from './WBC';
import extendedInstall, { getVuetifyInstance } from './extended_install';

let WBC;

const install = function (Vue, options = {}) {
    if (install.installed) return;
    install.installed = true;

    try {
        extendedInstall.install(Vue, options);

        if (!WBCOptions) console.error('[WBC] WBCOptions is UNDEFINED!');

        WBC = Vue.extend(WBCOptions);
        Vue.component('WBC', WBC);

        // Export to global for legacy browser environments
        if (global && typeof global !== 'undefined') {
            global.WBC = WBC;
        }
    } catch (e) {
        console.error('[WBC] Installation FAILED:', e);
    }
};

if (typeof window !== 'undefined' && window.Vue) {
    install(window.Vue);
}

import {
    WBHtml,
    WBLink,
} from './components';

import { safeEval, strToObj } from './utils/security.js';
import { setWbcRouteSink } from './utils/registerWbcRoute.js';
import { generalVal, clone, excludeList } from './utils/data.js';

export {
    WBCOptions as WBC,
    WBHtml,
    WBLink,
    getVuetifyInstance,
    safeEval,
    strToObj,
    setWbcRouteSink,
    generalVal,
    clone,
    excludeList,
};

export default {
    install,
    extendedInstall,
    WBC: WBCOptions
};
