/**
 * renderers/componentStrategies.js
 * Strategy pattern — individual component renderers extracted from renderObject.js
 * Each function: (self, h_, el, options, innerHtml, context) => VNode
 */
import { renderMissingComponentWarning } from './renderMissingComponentWarning.js';

/**
 * Strip a leading YAML frontmatter block (`---\n…\n---`) from markdown before it is
 * rendered, so page metadata (title, layout overrides, etc.) never shows as body
 * text. Standard gray-matter rule: the fence must be the very first thing in the
 * document. Guarded — only strips when the block is YAML-ish (has a `key:` line) —
 * so a document that merely OPENS with a horizontal-rule pair isn't truncated.
 */
export function stripFrontmatter(src) {
    if (typeof src !== 'string') return src;
    const m = src.match(/^﻿?---\r?\n([\s\S]*?)\r?\n---[ \t]*\r?\n?/);
    if (!m) return src;
    if (!/^[ \t]*[A-Za-z_][\w-]*[ \t]*:/m.test(m[1])) return src;
    return src.slice(m[0].length);
}

/**
 * Render slot entries from options.slots into template VNodes.
 * Shared helper used by all component strategies.
 */
export function renderSlots(self, h_, options) {
    return Object.entries(options?.slots || {}).map(
        ([slotName, slotVal]) =>
            h_("template", { slot: slotName }, [
                h_("WBC", {
                    key: `key-slots-${slotName}-${self.computedKey}`,
                    props: { item: slotVal },
                }),
            ])
    );
}

/**
 * Markdown renderer (comp == "MD")
 */
export function renderMarkdown(self, h_, el, options, innerHtml, { insideHeadersVN, insideFootersVN, extChildren }) {
    return h_(
        "div",
        {
            ref: "rawHtml",
            class: "markdown-body " + options?.class || "",
            ...options,
            on: self.itemListeners,
            key: `main-key-${self.computedKey}`,
        },
        [
            insideHeadersVN,
            innerHtml?.children || innerHtml,
            h_("WBHtml", {
                ...(options?.MDOptions || {}),
                props: {
                    html: self.$md.render(stripFrontmatter(options?.src) || ""),
                },
            }),
            ...renderSlots(self, h_, options),
            extChildren,
            insideFootersVN,
        ]
    );
}

/**
 * Mermaid diagram renderer (comp == "WBMermaid")
 */
export function renderMermaid(self, h_, el, options, innerHtml, { insideHeadersVN, insideFootersVN, extChildren }) {
    if (!self.$options.components['WBMermaid']) {
        return renderMissingComponentWarning('WBMermaid', h_);
    }
    return h_(
        "div",
        {
            ref: "rawHtml",
            class: "markdown-body " + options?.class || "",
            ...options,
            on: self.itemListeners,
        },
        [
            insideHeadersVN,
            innerHtml?.children || innerHtml,
            h_("WBMermaid", {
                ref: "rawHtml",
                props: {
                    src: options?.src || options?.props?.src || '',
                    wbcObj: options?.wbcObj || options?.props?.wbcObj || '',
                    ...(options || {}),
                },
                on: self.itemListeners,
            }),
            ...renderSlots(self, h_, options),
            extChildren,
            insideFootersVN,
        ]
    );
}

/**
 * Chart renderer (comp == "WBChart")
 */
export function renderChart(self, h_, el, options, innerHtml, { insideHeadersVN, insideFootersVN, extChildren }) {
    if (!self.$options.components['WBChart']) {
        return renderMissingComponentWarning('WBChart', h_);
    }
    return h_(
        "div",
        {
            ref: "rawHtml",
            ...options,
            on: self.itemListeners,
        },
        [
            insideHeadersVN,
            innerHtml?.children || innerHtml,
            h_("WBChart", {
                ...(options || {}),
                props: {
                    src: options.src || {},
                    ...(options?.props || {}),
                },
                on: self.itemListeners,
            }),
            ...renderSlots(self, h_, options),
            extChildren,
            insideFootersVN,
        ]
    );
}

/**
 * Code syntax highlighter renderer (comp == "WBCode")
 */
export function renderCode(self, h_, el, options, innerHtml, { insideHeadersVN, insideFootersVN, extChildren }) {
    if (!self.$options.components['WBCode']) {
        return renderMissingComponentWarning('WBCode', h_);
    }
    return h_(
        "div",
        {
            ref: "rawHtml",
            ...options,
            on: self.itemListeners,
            key:`key-${JSON.stringify(el)}`
        },
        [
            insideHeadersVN,
            innerHtml?.children || innerHtml,
            h_("WBCode", {
                props: {
                    code: options.src || "",
                    language: "markup",
                    inline: false,
                    ...(options?.props || {}),
                },
                class: `${options?.class || ""} language-${options?.props?.lang || "markup"
                    }`,
            }),
            ...renderSlots(self, h_, options),
            extChildren,
            insideFootersVN,
        ]
    );
}

/**
 * LaTeX / TeX renderer (comp == "tex" || "latex" || "WBLatex")
 */
export function renderLatex(self, h_, el, options, innerHtml, { insideHeadersVN, insideFootersVN, extChildren }) {
    if (!self.$options.components['WBLatex']) {
        return renderMissingComponentWarning('WBLatex', h_);
    }

    let theTex;
    // Note: the outer dispatch already ensures comp is one of tex/latex/WBLatex,
    // so this branch is always taken. The else branch is preserved for safety.
    theTex = h_("WBLatex", {
        props: {
            expression: options?.html || "",
            ...(options?.props || {}),
        },
        on: self.itemListeners,
    });

    return h_(
        options?.props?.["display-mode"] == true ? "div" : "span",
        {
            ref: "rawHtml",
            ...options,
        },
        [
            insideHeadersVN,
            theTex,
            ...renderSlots(self, h_, options),
            extChildren,
            insideFootersVN,
        ]
    );
}

/**
 * Icon renderer (comp == "VIcon")
 */
export function renderIcon(self, h_, el, options, innerHtml, { insideHeadersVN, insideFootersVN, extChildren }) {
    return h_(
        "span",
        {
            ref: "rawHtml",
        },
        [
            insideHeadersVN,
            h_(
                "VIcon",
                {
                    ref: "iconHtml",
                    ...options,
                    on: self.itemListeners,
                    key: `icon-${self.computedKey}`,
                },
                [
                    options?.html,
                ]
            ),
            extChildren,
            insideFootersVN,
        ]
    );
}

/**
 * Strategy map — maps comp names to renderer functions
 */
export const COMPONENT_STRATEGIES = {
    'MD': renderMarkdown,
    'WBMermaid': renderMermaid,
    'WBChart': renderChart,
    'WBCode': renderCode,
    'tex': renderLatex,
    'latex': renderLatex,
    'WBLatex': renderLatex,
    'VIcon': renderIcon,
};
