/**
 * renderers/scopeRenderer.js
 * Extracted from renderObject.js — handles the scope-based rendering of
 * no-comp objects whose values form a <tag> array pattern.
 *
 * Scope modes: container, root, each, each+merge, inherit, wrap-each, (default)
 * The 'update' scope is normalized to 'each+merge' before dispatch.
 */

/**
 * Reserved keys that are stripped from el before collecting HTML values.
 * Extracted as a constant to avoid re-allocation on every render cycle.
 */
export const KEYS_TO_AVOID = new Set([
    "comp", "output", "props", "options", "hOptions",
    "switch", "footer", "footers", "header", "headers",
    "hFooter", "hHeader", "asChild", "wrap", "to",
    "disp", "mode", "prod", "key", "fStyle",
    "dive", "tbDive", "watch", "forward",
    "class", "style", "id", "attrs",
]);

/**
 * Renders a no-comp object whose collected values form a WBC array pattern
 * (first item is a `<tag>` string). Dispatches to the appropriate scope mode.
 *
 * @param {Object} self - The WBC component instance (provides toWBC_, _stripScope, etc.)
 * @param {Function} h_ - The createElement function
 * @param {Array} theHtml - Collected non-reserved values from the element
 * @param {Object} el - The original element definition
 * @returns {VNode|null} The rendered VNode, or null if not a tag-array pattern
 */
export function renderScopedArray(self, h_, theHtml, el) {
    // Guard: must be a tag-array pattern
    if (
        !Array.isArray(theHtml) ||
        theHtml.length === 0 ||
        typeof theHtml[0] !== 'string' ||
        !theHtml[0].startsWith('<') ||
        !theHtml[0].endsWith('>')
    ) {
        return null; // Signal: not handled, caller should use fallback
    }

    const elOpts = el?.options;
    const hasMeaningfulOpts =
        elOpts && typeof elOpts === 'object' &&
        Object.keys(elOpts).some(k => k !== 'wrap' && k !== 'scope');
    const hasTildeRoot = theHtml[0].includes('~');
    const userScope = elOpts?.scope;
    const scope = userScope || (hasTildeRoot ? 'root' : 'container');

    const cleanOpts = self._stripScope(elOpts || {});
    const normScope = scope === 'update' ? 'each+merge' : scope;

    // --- Scope dispatch ---

    if (!hasMeaningfulOpts) {
        return self.toWBC_(theHtml, h_);
    }

    if (normScope === 'container') {
        const wrapComp = elOpts.comp || 'div';
        return self.toWBC_(
            { comp: wrapComp, options: cleanOpts },
            h_,
            self.toWBC_(theHtml, h_)
        );
    }

    if (normScope === 'root' && hasTildeRoot) {
        const merged = self._mergeTagWithOptions(theHtml[0], cleanOpts, false);
        const mergedStr = self._wbcObjToTagStr(merged);
        const newArr = [mergedStr || theHtml[0], ...theHtml.slice(1)];
        return self.toWBC_(newArr, h_);
    }

    if (normScope === 'root' && !hasTildeRoot) {
        return self.toWBC_(
            { comp: elOpts.comp || 'div', options: cleanOpts },
            h_,
            self.toWBC_(theHtml, h_)
        );
    }

    if (normScope === 'each' || normScope === 'each+merge' || normScope === 'inherit') {
        const replace = normScope === 'each';
        const start = hasTildeRoot ? 1 : 0;
        const rebuilt = [];
        if (hasTildeRoot) rebuilt.push(theHtml[0]);
        for (let i = start; i < theHtml.length; i++) {
            const child = theHtml[i];
            const isTagStr = typeof child === 'string' && child.startsWith('<') && child.endsWith('>');
            if (!isTagStr) { rebuilt.push(child); continue; }
            if (normScope === 'inherit' && self._tagHasOptions(child)) {
                rebuilt.push(child);
            } else {
                const obj = self._mergeTagWithOptions(child, cleanOpts, replace);
                const asStr = self._wbcObjToTagStr(obj);
                rebuilt.push(asStr || obj);
            }
        }
        return self.toWBC_(rebuilt, h_);
    }

    if (normScope === 'wrap-each') {
        const wrapComp = elOpts.comp || 'span';
        const start = hasTildeRoot ? 1 : 0;
        const rebuilt = [];
        if (hasTildeRoot) rebuilt.push(theHtml[0]);
        for (let i = start; i < theHtml.length; i++) {
            rebuilt.push({ comp: wrapComp, options: { ...cleanOpts, html: theHtml[i] } });
        }
        return self.toWBC_(rebuilt, h_);
    }

    // Default fallback
    return self.toWBC_(theHtml, h_);
}
