import { FILE_EXTENSIONS, YOUTUBE_PATTERNS, LANG_MAP } from '../constants';
import { renderFile } from './renderFile';
import { stripFrontmatter } from './componentStrategies.js';

const __DEV__ = typeof __WBC_DEV__ !== 'undefined'
    ? __WBC_DEV__
    : (typeof process !== 'undefined' && process.env
        ? process.env.NODE_ENV !== 'production'
        : false);

/**
 * Sentinel used to preserve literal pipes during the el.split("|") parse.
 * Users write `\|` in their item strings to emit a real pipe character
 * instead of triggering the field-delimiter logic.
 * @private
 */
const _PIPE_PLACEHOLDER = '\x00PIPE\x00';
const _PIPE_PLACEHOLDER_RE = /\x00PIPE\x00/g;

function _parseElement(el, self) {
    // Escape sequence: replace \| with placeholder before splitting on |
    const escaped = el.replace(/\\\|/g, _PIPE_PLACEHOLDER);
    const parts = escaped.split("|").map(s => s.replace(_PIPE_PLACEHOLDER_RE, '|'));
    const [el1, classOrOptionsRaw, theFileLink, parsedAs] = parts;
    const classOrOptions = self.strToObj(classOrOptionsRaw);
    const classOrOptionsObj = self.isPlainObject(classOrOptions)
        ? classOrOptions
        : self.isNonEmpty(classOrOptions) ? { class: classOrOptions || {} } : {};

    const ext = el1.split('.').pop()?.toLowerCase();
    const fileLanguage = LANG_MAP[ext] || null;

    return { el1, classOrOptionsObj, theFileLink, parsedAs, ext, fileLanguage };
}

function _getLocalFileFromContext(self, type, src) {
    const contexts = self.getContext();
    if (!contexts) {
        throw new Error(`File type "${type}" is not supported.`);
    }
    const cleanSrc = src;
    const tryContext = (ctx) => {
        try {
            if (!ctx || typeof ctx !== "function") return null;
            const keys = ctx.keys ? ctx.keys() : [];
            if (keys.includes(cleanSrc)) {
                const module = ctx(cleanSrc);
                return module?.default !== undefined ? module.default : module;
            }
            // Vite glob keys retain ./ prefix, but resolvers strip it — retry with ./
            const withDotSlash = cleanSrc.startsWith('./') ? null : './' + cleanSrc;
            if (withDotSlash && keys.includes(withDotSlash)) {
                const module = ctx(withDotSlash);
                return module?.default !== undefined ? module.default : module;
            }
        } catch (e) { }
        return null;
    };
    return tryContext(contexts);
}

function _loadSource(self, elPath, type) {
    return self.loadFile(elPath) || _getLocalFileFromContext(self, type, elPath);
}

function _resolveCodeFile(el, h_, self, opts) {
    const { el1, classOrOptionsObj, parsedAs, ext, fileLanguage } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    let source, contentType, lang;
    const parsedLower = parsedAs?.toLowerCase();

    const typeMap = [
        { test: el1.includes(".vue") || parsedLower === "vue", type: "vue", contentType: "text/x-vue", lang: 'html' },
        { test: el1.includes(".py") || ["py", "python"].includes(parsedLower), type: "py", contentType: "text/x-python", lang: 'python' },
        { test: el1.includes(".rs") || ["rs", "rust"].includes(parsedLower), type: "rs", contentType: "text/x-rust", lang: 'rust' },
        { test: el1.includes(".css") || parsedLower === "css", type: "css", contentType: "text/css", lang: 'css' },
        { test: el1.includes(".scss") || parsedLower === "scss", type: "scss", contentType: "text/css", lang: 'css' },
        { test: el1.includes(".sass") || parsedLower === "sass", type: "sass", contentType: "text/css", lang: 'css' },
        { test: el1.includes(".php") || parsedLower === "php", type: "php", contentType: "application/x-httpd-php", lang: 'php' },
        { test: el1.includes(".sh") || parsedLower === "sh", type: "sh", contentType: "text/html", lang: 'html' },
        { test: el1.includes(".js") || el1.includes(".ts") || el1.includes(".json") || ["js", "ts", "json"].includes(parsedLower), type: "js", contentType: "text/javascript", lang: 'javascript' },
        { test: el1.includes(".md") || parsedLower === "md", type: "md", contentType: "text/x-markdown", lang: 'markdown' },
        { test: el1.includes(".tex") || parsedLower === "tex", type: "tex", contentType: "text/html", lang: 'html' },
        { test: el1.includes(".txt") || parsedLower === "txt", type: "txt", contentType: "text/html", lang: 'text' },
        { test: el1.includes(".html") || parsedLower === "html", type: "html", contentType: "text/html", lang: 'markup' },
        { test: el1.includes(".c") || el1.includes(".cpp") || ["c", "cpp"].includes(parsedLower), type: "c", contentType: "text/x-csrc", lang: 'c' },
    ];

    const match = typeMap.find(t => t.test);
    if (match) {
        source = _loadSource(self, elPath, match.type);
        lang = match.lang;
        contentType = match.contentType;
    }

    if (source === undefined) source = _loadSource(self, elPath, ext || 'text');

    if (!(source || self.fileContent)) {
        throw new Error(`#CodeFileError: ${el1} not found`);
    }

    const WBCodItemProps = {
        language: lang || fileLanguage || 'WBC',
        extra: elPath,
        ...(typeof (self.resolvedWbCodeFile) == 'boolean' ? {} : self.resolvedWbCodeFile || {}),
    };

    const fileWbCodeObj = self.renderDefaultWbcode(h_, source, WBCodItemProps);

    return source
        ? h_('WBC', {
            ...classOrOptionsObj,
            props: { item: fileWbCodeObj }
        })
        : self.fileContent;
}

function _resolveJsonFile(el, h_, self, opts) {
    const { el1, classOrOptionsObj } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    self.source = _loadSource(self, elPath, "json");
    try {
        self.source = typeof self.source === "string" ? JSON.parse(self.source) : self.source;
    } catch (e) { }

    if (!(self.source || self.fileContent)) {
        throw new Error(`#JsonFileError: ${el1} not found`);
    }

    if (self.source) {
        return self.source.WBC
            ? h_("WBC", { ref: "rawHtml", title: el1, props: { item: self.source.WBC }, ...classOrOptionsObj })
            : h_("JsonViewer", { ref: "rawHtml", title: el1, props: { value: self.source }, ...classOrOptionsObj });
    }
    return self.fileContent;
}

function _resolveTxtFile(el, h_, self, opts) {
    const { el1, classOrOptionsObj, parsedAs } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    self.source = _loadSource(self, elPath, "txt");
    if (!(self.source || self.fileContent)) {
        throw new Error(`#TxtFileError: ${el1} not found`);
    }

    const jsLang = el1.endsWith(".txt") ? "txt" : "text";
    const WBCodItemProps = {
        language: jsLang,
        extra: elPath,
        ...(typeof (self.resolvedWbCodeFile) == 'boolean' ? {} : self.resolvedWbCodeFile || {}),
    };
    return h_('WBC', {
        ...classOrOptionsObj,
        props: { item: self.renderDefaultWbcode(h_, self.source, WBCodItemProps) }
    });
}

function _resolveJsFile(el, h_, self, opts) {
    const { el1, classOrOptionsObj, parsedAs } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    const parsedLower = parsedAs?.toLowerCase();
    self.source = _loadSource(self, elPath, "js");

    if (!(self.source || self.fileContent)) {
        throw new Error(`#JsFileError: ${el1} not found`);
    }

    // String source — detect Vue component, logic injector, or plain code
    if (typeof self.source === "string") {
        const looksLikeVueComponent = (
            /export\s+default/i.test(self.source) &&
            /(render\s*\(|setup\s*\(|template\s*[:=`'"]|setup\s*[:=`'"])/i.test(self.source)
        );
        const isLogicSource = self.source.includes('@wbc-logic') || self.source.includes('@wbc-mixin');

        if (looksLikeVueComponent || isLogicSource || parsedLower === "vue") {
            if (!self._jsLazyComp && !self._jsLazyLoading) {
                self._jsLazyLoading = true;
                const contexts = self.getContext();
                const lazyPromise = contexts?.lazyImport?.(el1);
                if (lazyPromise) {
                    const h_inst = self.$createElement;
                    lazyPromise.then(mod => {
                        const comp = mod?.default || mod;
                        const ctx = self.itemAccessibility;
                        const isLogicMod = (
                            mod.setup || mod.init || mod.tracker || mod.logic ||
                            (typeof comp === 'function' && isLogicSource)
                        );

                        if (isLogicMod) {
                            const _isWBC_PRO = typeof __WBC_PRO__ !== 'undefined' ? __WBC_PRO__ : false;
                            const _authorized = self.$store?.getters?._wbcProAuthorized !== false;
                            if (mod.init) mod.init(ctx);
                            if ((_isWBC_PRO && _authorized) || __DEV__) {
                                if (mod.setup) mod.setup(ctx);
                                if (mod.tracker) mod.tracker(ctx);
                                if (mod.logic) mod.logic(ctx);
                                if (typeof comp === 'function' && isLogicSource) comp(ctx);
                            } else if (isLogicMod && !mod.init) {
                                console.warn("[WBC-UI2] Advanced JS features (setup/tracker/logic) require a PRO license.");
                            }

                            self._jsLazyComp = {
                                render: h => h('div', {
                                    class: 'caption grey--text pa-1 px-2 border-dashed blue lighten-5 rounded d-inline-block'
                                }, [h('v-icon', { props: { xSmall: true, left: true, color: 'blue' } }, 'mdi-cog-outline'), `Logic Provider: ${elPath}`])
                            };
                            self._jsLazyLoading = false;
                        } else if (comp && typeof comp === 'object' && (comp.render || comp.setup || comp.template)) {
                            self._jsLazyComp = { ...comp };
                            self._jsLazyLoading = false;
                        } else {
                            self._jsLazyLoading = false;
                            self.fileContent = self.renderDefaultWbcode(h_inst, self.source, { language: 'javascript', extra: elPath });
                        }
                        self.$forceUpdate();
                    }).catch(err => {
                        self._jsLazyLoading = false;
                        self.fileContent = self.renderDefaultWbcode(h_inst, self.source, { language: 'javascript', extra: elPath });
                        self.$forceUpdate();
                    });
                } else {
                    self._jsLazyLoading = false;
                    self.fileContent = self.renderDefaultWbcode(self.$createElement, self.source, { language: 'javascript', extra: elPath });
                }
            }

            if (self._jsLazyComp) {
                return h_(self._jsLazyComp, {
                    props: self.props_ || self._jsLazyComp.params || {},
                    ...classOrOptionsObj,
                });
            }
            return self.fileContent || h_("VProgressLinear", { props: { indeterminate: true, color: "blue", height: 2 } });
        }

        // Plain script — render as code block
        const jsLang = el1.endsWith(".ts") ? "typescript" : "javascript";
        const WBCodItemProps = {
            language: jsLang,
            extra: elPath,
            ...(typeof (self.resolvedWbCodeFile) == 'boolean' ? {} : self.resolvedWbCodeFile || {}),
        };
        return h_('WBC', {
            ...classOrOptionsObj,
            props: { item: self.renderDefaultWbcode(h_, self.source, WBCodItemProps) }
        });
    }

    // Object source
    if (self.source && typeof self.source === "object") {
        const ctx = self.itemAccessibility;
        if (self.source.setup || self.source.init || self.source.tracker || self.source.logic) {
            const _isWBC_PRO = typeof __WBC_PRO__ !== 'undefined' ? __WBC_PRO__ : false;
            const _authorized = self.$store?.getters?._wbcProAuthorized !== false;
            if (self.source.init) self.source.init(ctx);
            if ((_isWBC_PRO && _authorized) || __DEV__) {
                if (self.source.setup) self.source.setup(ctx);
                if (self.source.tracker) self.source.tracker(ctx);
                if (self.source.logic) self.source.logic(ctx);
            } else if (self.source.setup || self.source.tracker || self.source.logic) {
                console.warn("[WBC-UI2] Advanced Object features (setup/tracker/logic) require a PRO license.");
            }
            return h_('div', { class: 'caption blue--text px-2 border-dashed rounded' }, ['Executed Object Logic: ' + elPath]);
        }
        if (self.source.render || self.source.setup || self.source.template) {
            return h_(self.source, {
                props: self.props_ || self.source.params || {},
                ...classOrOptionsObj,
            });
        }
        return h_("WBC", { props: { item: self.source }, ...classOrOptionsObj });
    }

    // Function source
    if (typeof self.source === "function") {
        if (self.source.toString().includes('@wbc-logic')) {
            const _isWBC_PRO = typeof __WBC_PRO__ !== 'undefined' ? __WBC_PRO__ : false;
            const _authorized = self.$store?.getters?._wbcProAuthorized !== false;
            if ((_isWBC_PRO && _authorized) || __DEV__) {
                self.source(self.itemAccessibility);
            } else {
                console.warn("[WBC-UI2] Dynamic Logic Injection Functions (@wbc-logic) require a PRO license.");
            }
            return h_('div', { class: 'caption blue--text px-2 border-dashed rounded' }, ['Executed Logic Function: ' + elPath]);
        }

        const funcSource = self.source.toString();
        return h_('WBC', {
            ...classOrOptionsObj,
            props: {
                item: self.renderDefaultWbcode(h_, funcSource, {
                    language: 'javascript',
                    extra: elPath,
                    output: {
                        header: { 0: '<~VRow,pb-1 grey grey--text lighten-2 font-weight-bold mb-1>', 1: `small__${elPath} (Function)`, 2: 'VSpacer', 3: 'download', 4: 'copy' },
                        main: { 1: 'code' },
                        terminus: { 0: '<~VRow,pt-1 grey grey--text lighten-4 mt-1>', 1: 'small__WBC-function-self.source', 2: 'VSpacer' }
                    }
                })
            }
        });
    }

    return h_("v-alert", {
        props: { type: "warning", border: "left", coloredBorder: true, elevation: 2, icon: "mdi-alert-circle" },
        class: "my-2 pa-2 orange--text",
    }, [
        h_("div", { class: "font-weight-bold" }, "Unknown Content Type"),
        h_("div", `The file "${el1}" returned a value of type "${typeof self.source}".`),
        h_("div", { class: "caption mt-1 d-block" }, "WBC lacks a direct renderer for this data type. Check the console for more details."),
    ]);
}

function _resolveCssFile(el, h_, self, opts) {
    const { el1, classOrOptionsObj, parsedAs } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    self.source = _loadSource(self, elPath, "css");
    const parsedLower = parsedAs?.toLowerCase();

    if (parsedLower === "txt" || parsedLower === "md") {
        const WBCodItemProps = {
            language: "css",
            extra: elPath,
            ...(typeof (self.resolvedWbCodeFile) == 'boolean' ? {} : self.resolvedWbCodeFile || {}),
        };
        return h_('WBC', {
            ...classOrOptionsObj,
            props: { item: self.renderDefaultWbcode(h_, self.source, WBCodItemProps) }
        });
    }
    return h_('style', {
        attrs: { type: 'text/css' },
        domProps: { textContent: self.source }
    });
}

function _resolveVueFile(el, h_, self, opts) {
    const { el1, classOrOptionsObj } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    self.source = _loadSource(self, elPath, "vue");
    if (!(self.source || self.fileContent)) {
        throw new Error(`#VueFileError: ${el1} not found`);
    }
    return self.source
        ? h_(self.source?.default || self.source, {
            props: self.source?.default?.params || self.props_ || {},
            ...classOrOptionsObj,
        })
        : self.fileContent;
}

function _resolveTextFile(el, h_, self, opts) {
    const { el1, classOrOptionsObj, parsedAs } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    const theExtension = el1.split(".").pop()?.toLowerCase();
    const parsedLower = parsedAs?.toLowerCase();
    self.source = _loadSource(self, elPath, theExtension);

    // TEX/Latex files
    if (parsedLower === "tex" || parsedLower === "latex" || (theExtension === "tex" && !parsedAs)) {
        if (!self.$options.components['WBLatex']) {
            return h_("div", {
                style: { backgroundColor: "#F8F9FA", color: "red", width: "100%", height: "100%", margin: "10px" },
            }, [`#WBLatexMissing: "wb-latex" not registered`]);
        }
        if (!(self.source || self.fileContent)) {
            throw new Error(`#TexFileError: ${el1} not found`);
        }
        return self.source
            ? h_("div", { ref: "rawHtml", title: el1, ...classOrOptionsObj }, [
                h_("div", self.parseTexFile(self.source).map((block) => {
                    if (block.type === "text") return h_("div", [h_("WBHtml", { props: { html: block.content } })]);
                    if (block.type === "math") return h_("WBLatex", { props: { expression: block.expression, "display-mode": block.displayMode ?? false } });
                    if (block.type === "mixed") {
                        return h_("div", { class: "d-inline-flex align-center" },
                            block.lineContent.map((part) =>
                                part.expression
                                    ? h_("WBLatex", { props: { expression: part.expression, "display-mode": false } })
                                    : h_("WBHtml", { props: { html: part.content } })
                            )
                        );
                    }
                }))
            ])
            : self.fileContent;
    }

    // Markdown files
    if (["md", "markdown", "markup"].includes(parsedLower) || (theExtension === "md" && !parsedAs)) {
        if (!(self.source || self.fileContent)) {
            throw new Error(`#MdFileError: ${el1} not found`);
        }
        return self.source
            ? h_("WBHtml", { ref: "rawHtml", props: { html: self.$md.render(stripFrontmatter(self.source)) }, ...classOrOptionsObj })
            : self.fileContent;
    }

    // HTML / plain text files
    if (!(self.source || self.fileContent)) {
        throw new Error(`#HtmlFileError: ${el1} not found`);
    }
    return self.source
        ? h_("WBHtml", { ref: "rawHtml", props: { html: self.source }, ...classOrOptionsObj })
        : self.fileContent;
}

function _resolveMediaFile(el, h_, self, opts) {
    const { el1, classOrOptionsObj, parsedAs } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    const parsedLower = parsedAs?.toLowerCase();

    if (self._matchesFileType(el1, FILE_EXTENSIONS.IMAGE) || ["image", "img", "png", "jpg", "jpeg", "gif", "svg"].includes(parsedLower)) {
        self.source = _loadSource(self, elPath, "image");
        if (!(self.source || self.fileContent)) throw new Error(`#ImageFileError: ${el1} not found`);
        return self.source
            ? h_("img", { attrs: { src: `${self.source}`.replace("/js/", "/") }, class: "container", ref: "rawHtml", ...classOrOptionsObj })
            : self.fileContent;
    }

    if (self._matchesFileType(el1, FILE_EXTENSIONS.VIDEO) || ["video", "mp4", "webm"].includes(parsedLower)) {
        self.source = _loadSource(self, elPath, "video") || (el1.startsWith("/") ? el1 : null);
        if (!(self.source || self.fileContent)) throw new Error(`#VideoFileError: ${el1} not found`);
        return self.source ? self._renderVideo(h_, self.source, classOrOptionsObj) : self.fileContent;
    }

    if (self._matchesFileType(el1, FILE_EXTENSIONS.AUDIO) || ["audio", "mp3", "wav"].includes(parsedLower)) {
        self.source = _loadSource(self, elPath, "audio");
        if (!(self.source || self.fileContent)) throw new Error(`#AudioFileError: ${el1} not found`);
        return self.source ? self._renderAudio(h_, self.source, classOrOptionsObj) : self.fileContent;
    }

    return null;
}

function _resolveOfficeFile(el, h_, self, opts) {
    const { el1, classOrOptionsObj } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    self.source = _loadSource(self, elPath, "office");
    if (!(self.source || self.fileContent)) throw new Error(`#OfficeFileError: ${el1} not found`);

    if (self._matchesFileType(el1, FILE_EXTENSIONS.OFFICE.DOCX)) {
        return h_("VueOfficeDocx", { props: { src: self.source }, class: "container", style: { top: 0, left: 0 }, ref: "rawHtml" });
    }
    if (self._matchesFileType(el1, FILE_EXTENSIONS.OFFICE.XLSX)) {
        return h_("VueOfficeExcel", { props: { src: self.source }, class: "container white", style: { top: 0, left: 0, height: "100vh", width: "100vh" }, ref: "rawHtml" });
    }
    return h_("VueDocPreview", { props: { value: self.source, type: "office" }, class: "container", style: { top: 0, left: 0, width: "100vh", height: "100vh" }, ref: "rawHtml" });
}

function _resolvePdfFile(el, h_, self, opts) {
    const { el1 } = opts;
    const elPath = el1.startsWith("./") ? el1.substring(2) : el1;
    self.source = _loadSource(self, elPath, "pdf");
    if (!(self.source || self.fileContent)) throw new Error(`#PdfFileError: ${el1} not found`);
    return self.source
        ? h_("iframe", { attrs: { src: self.source }, class: "container white", style: { top: 0, left: 0, height: "100vh", width: "100vh", border: 0 }, ref: "rawHtml" })
        : self.fileContent;
}

function _resolveLocalFile(el, h_, self, opts) {
    const { el1, parsedAs } = opts;
    const parsedLower = parsedAs?.toLowerCase();
    const theMediaArr = el.split("/");

    // Code-like files
    if (
        theMediaArr[theMediaArr.length - 1]?.startsWith("__") ||
        self._matchesFileType(el, FILE_EXTENSIONS.CODE) ||
        ["py", "python", "php", "c", "cpp", "sh", "rs", "rust", "code"].includes(parsedLower)
    ) {
        return _resolveCodeFile(el, h_, self, opts);
    }

    // JSON
    if (el1.endsWith(".json") || parsedLower === "json") {
        return _resolveJsonFile(el, h_, self, opts);
    }

    // TXT
    if (el1.endsWith(".txt") || parsedLower === "txt" || parsedLower === "text") {
        return _resolveTxtFile(el, h_, self, opts);
    }

    // JS/TS
    if (parsedLower === "js" || parsedLower === "ts" || ((el1.endsWith(".js") || el1.endsWith(".ts")) && !parsedAs)) {
        return _resolveJsFile(el, h_, self, opts);
    }

    // CSS/Style
    if (self._matchesFileType(el, FILE_EXTENSIONS.STYLE) || ["css", "scss", "sass", "style"].includes(parsedLower)) {
        return _resolveCssFile(el, h_, self, opts);
    }

    // Vue
    if (el1.endsWith(".vue") || parsedLower === "vue") {
        return _resolveVueFile(el, h_, self, opts);
    }

    // Text/Markdown/HTML
    if (self._matchesFileType(el, FILE_EXTENSIONS.TEXT)) {
        return _resolveTextFile(el, h_, self, opts);
    }

    // Media (Image/Video/Audio)
    const mediaResult = _resolveMediaFile(el, h_, self, opts);
    if (mediaResult !== null) return mediaResult;

    // Office
    if (self._matchesFileType(el, [...FILE_EXTENSIONS.OFFICE.DOCX, ...FILE_EXTENSIONS.OFFICE.XLSX, ...FILE_EXTENSIONS.OFFICE.GENERAL]) || ["office", "docx", "xlsx", "doc", "xls", "pptx"].includes(parsedLower)) {
        return _resolveOfficeFile(el, h_, self, opts);
    }

    // PDF
    if (el1.endsWith(".pdf") || parsedLower === "pdf") {
        return _resolvePdfFile(el, h_, self, opts);
    }

    // Fallback
    if (!self.fileContent) {
        renderFile(self, h_, el, opts.classOrOptionsObj);
    }
    return self.fileContent;
}

function _resolveOnlineResource(el, h_, self, opts) {
    const { el1, classOrOptionsObj, parsedAs, theFileLink } = opts;
    const parsedLower = parsedAs?.toLowerCase();

    if (self._matchesFileType(el, FILE_EXTENSIONS.OFFICE.DOCX)) {
        return h_("VueOfficeDocx", { props: { src: el1 }, class: "container", style: { top: 0, left: 0 }, ref: "rawHtml" });
    }
    if (self._matchesFileType(el, FILE_EXTENSIONS.OFFICE.XLSX)) {
        return h_("VueOfficeExcel", { props: { src: el1 }, class: "container white", style: { top: 0, left: 0, height: "100vh", width: "100vh" }, ref: "rawHtml" });
    }
    if (self._matchesFileType(el, FILE_EXTENSIONS.OFFICE.GENERAL)) {
        return h_("VueDocPreview", { props: { url: el1, type: "office" }, class: "container", style: { top: 0, left: 0, width: "100vh", height: "100vh" }, ref: "rawHtml" });
    }
    if (self._matchesFileType(el, FILE_EXTENSIONS.AUDIO)) {
        return self._renderAudio(h_, el1, classOrOptionsObj);
    }
    if (self._matchesFileType(el, FILE_EXTENSIONS.IMAGE)) {
        return self._renderImage(h_, el1, classOrOptionsObj);
    }
    if (self._matchesFileType(el, FILE_EXTENSIONS.VIDEO)) {
        return self._renderVideo(h_, el1, classOrOptionsObj);
    }
    // YouTube
    if (YOUTUBE_PATTERNS.some(pattern => el.includes(pattern)) && !el.includes("embed")) {
        return self._renderYouTube(h_, el1, classOrOptionsObj);
    }
    // Code/Text/Style — fetch remotely
    if (
        self._matchesFileType(el, FILE_EXTENSIONS.CODE) ||
        self._matchesFileType(el, FILE_EXTENSIONS.TEXT) ||
        self._matchesFileType(el, FILE_EXTENSIONS.STYLE) ||
        self._matchesFileType(el, ['.js', '.ts', '.json', '.vue', '.jsx', '.tsx', '.mmd'])
    ) {
        if (!self.mediaData && !self.fileContent) {
            const langMapExtended = { ...LANG_MAP, jsx: 'javascript', tsx: 'typescript', mmd: 'markdown' };
            const ext = el1.split('.').pop()?.split('?')[0]?.toLowerCase();
            const fileLanguage = langMapExtended[ext] || 'text';

            self.content["promise"] = fetch(el1)
                .then(response => response.text())
                .then(data => {
                    if (ext === 'md' && self.$md) {
                        self.fileContent = h_("WBHtml", {
                            props: { html: self.$md.render(stripFrontmatter(data) || "") },
                            ...classOrOptionsObj,
                        });
                    } else {
                        const WBCodItemProps = {
                            language: fileLanguage,
                            topBar: null,
                            codeBar: [[`${el1}|green`, 'filename'], ['download', 'copy']],
                            outputFn: null,
                            extra: el1,
                        };
                        self.fileContent = self.renderDefaultWbcode(h_, data, WBCodItemProps);
                    }
                })
                .catch(() => {
                    self.fileContent = h_("iframe", {
                        attrs: { src: el1, frameborder: "0", allowfullscreen: true, referrerpolicy: "strict-origin-when-cross-origin" },
                        class: "container white",
                        style: { resize: "both", top: 0, left: 0, height: "100%", width: "100%", border: 0 },
                        ref: "rawHtml",
                        ...classOrOptionsObj,
                    });
                });
        }
        return self.fileContent;
    }

    // Fallback
    if (!self.mediaData && !self.fileContent) {
        renderFile(self, h_, el1, classOrOptionsObj);
    }
    return self.fileContent;
}

function _resolveComponentTag(el, h_, self) {
    if (
        typeof el === "string" &&
        el.startsWith("<") &&
        el.endsWith(">") &&
        (el.match(/</g) || []).length === 1 &&
        (el.match(/>/g) || []).length === 1
    ) {
        let content = el.slice(1, -1);
        if (content.startsWith("~")) content = content.slice(1);
        
        const [tagAndClass, link] = content.split("|");
        const [tagName, tagClass] = tagAndClass.split(",").map(s => s.trim());

        const tagAttrs = {
            ref: "rawHtml",
            class: tagClass || undefined,
        };

        if (link) {
            tagAttrs.attrs = { href: link.trim() };
        }

        return h_(tagName, tagAttrs);
    }
    return null;
}

/**
 * Resolve a relative path (./file, ../../file) against the parent component's
 * file location. Used in "no context" mode where local files are fetched from
 * the dev server relative to the component that uses <WBC>.
 *
 * Falls back to serving from root if __file is not available.
 */
function _resolveRelativePath(self, relativePath) {
    // Resolve against the nearest ANCESTOR Vue SFC — the closest component up the render
    // chain that owns a __file. We walk `$vnode.context` (the instance whose render created
    // each vnode), which handles both shapes:
    //   • Direct  <WBC item="./x"/> in an SFC  → finds the host SFC immediately. Robust
    //     against slot nesting: inside Vuetify <v-app>/<v-main>, $parent is VMain (a
    //     precompiled component with NO __file), but $vnode.context is the authoring SFC.
    //   • Data-driven (WBGC rendering a viewComps tree, e.g. `menu:'./img0.jpeg'` in
    //     _viewComps.js): the WBC has no authoring SFC, so we climb WBC → … → WBGC → host
    //     SFC. WBGC is a plain options object with no __file, so a single hop isn't enough.
    // The host SFC's directory anchors "./x"; by this app's convention a view's
    // _viewComps.js is colocated with its host SFC, so the data-driven "./img0.jpeg"
    // resolves to the same file as the direct usage. ($parent is a secondary hop when
    // $vnode is absent.) Vue 2 SFCs carry __file in dev (set by @vitejs/plugin-vue2).
    let parentFile = null;
    let node = self;
    const seen = new Set();
    while (node && !seen.has(node)) {
        seen.add(node);
        const opts = node.$options || {};
        if (opts.__file || opts.file) { parentFile = opts.__file || opts.file; break; }
        node = node.$vnode?.context || node.$parent || null;
    }

    if (!parentFile) {
        // Fallback: strip ./ and serve from root
        console.warn(`[WBC] No __file found on any authoring ancestor. Cannot resolve "${relativePath}" relatively. Serving from root.`);
        return '/' + relativePath.replace(/^\.[\/]/, '');
    }

    // Get directory of parent component
    const parentDir = parentFile.substring(0, parentFile.lastIndexOf('/') + 1);

    // Resolve relative path against parent directory
    const combined = parentDir + relativePath.replace(/^\.[\/]/, '');
    const segments = combined.split('/');
    const resolved = [];
    for (const seg of segments) {
        if (seg === '..') resolved.pop();
        else if (seg !== '.' && seg !== '') resolved.push(seg);
    }

    let finalPath = '/' + resolved.join('/');
    
    // In Vite, absolute filesystem paths (like /home/...) must be prefixed with /@fs/ to be fetched
    if (finalPath.startsWith('/home/') || finalPath.startsWith('/Users/') || finalPath.match(/^\/[a-zA-Z]:\//)) {
        finalPath = '/@fs' + finalPath;
    }

    return finalPath;
}

export function renderString(self, el, h_, context) {
    let main;

    // WBHtml markup short-circuit: when the string contains `{{` or `[[`
    // delimiters, pipes belong to WBHtml's `tag|class|link` grammar inside
    // those delimiters — not to renderString's `text|class|link|parsedAs`
    // grammar. Splitting on `|` here would corrupt the markup (e.g. pull
    // `]][[li__...` into parsedAs and crash on h(parsedAs, ...)).
    if (typeof el === 'string' && (el.includes('{{') || el.includes('[['))) {
        return h_("WBHtml", {
            ref: "rawHtml",
            keyy: `wbhtml-key-${self.computedKey}-${el.length}`,
            props: { html: el },
        });
    }

    // Object/array pipe-shorthand (`<tag>__[...]` / `<tag>__{...}`, or a bare `[...]`/`{...}`
    // carrying a pipe). The content literal holds its OWN inner `text|class|link` pipes,
    // which renderString's flat `text|class|link|parsedAs` split (_parseElement) would
    // corrupt — an inner link shifts a later field into `parsedAs`, then `h(parsedAs, …)`
    // below calls createElement with an invalid tag (e.g. `red pa-2__pink pa-12`). Delegate
    // to WBHtml's depth-aware `_parsePipeForm`, the single authority for this grammar
    // (mirrors the `[[`/`{{` short-circuit above).
    if (typeof el === 'string' && el.includes('|')) {
        const afterTag = el.replace(/^[a-zA-Z][\w-]*__/, '').trimStart();
        if (afterTag.startsWith('[') || afterTag.startsWith('{')) {
            return h_("WBHtml", {
                ref: "rawHtml",
                keyy: `wbhtml-key-${self.computedKey}-${el.length}`,
                props: { html: el },
            });
        }
    }

    const opts = _parseElement(el, self);
    const { el1, classOrOptionsObj, theFileLink, parsedAs } = opts;
    const pathType = self._getPathType(el);
    const parsedLower = parsedAs?.toLowerCase();
    let delegatedPipesToWBHtml = false;

    if (pathType === 'local') {
        if (self.$wbcUi2Options?.context) {
            // Context mode: resolve via pre-bundled require.context map (sync)
            main = _resolveLocalFile(el, h_, self, opts);
        } else {
            // Relative mode: no context provided — resolve path relative to
            // parent component's file location and fetch from dev server
            const resolvedPath = _resolveRelativePath(self, el1);
            if (!self.mediaData && !self.fileContent) {
                renderFile(self, h_, resolvedPath, classOrOptionsObj);
            }
            main = self.fileContent;
        }
    } else if (pathType === 'served' || pathType === 'online') {
        if (pathType === 'served') {
            if (!self.mediaData && !self.fileContent) {
                renderFile(self, h_, el1, classOrOptionsObj);
            }
            main = self.fileContent;
        } else {
            main = _resolveOnlineResource(el, h_, self, opts);
        }
    } else {
        // Try component tag syntax
        main = _resolveComponentTag(el, h_, self);
        if (!main) {
            // Delegate the raw pipe-containing string to WBHtml when class/link
            // fields are present (with or without a `tag__` prefix). WBHtml's
            // styling() pipeline turns `[tag__]text|class|link` into the array
            // form that applies class to the inner tag/span — same path the
            // object input takes via { comp, options: { html: '...' } }.
            // Plain text without pipes keeps the pre-parsed el1 path so escape
            // decoding (\| → |) handled here is preserved.
            const hasPipeFields = self.isNonEmpty(opts.classOrOptionsObj) || !!theFileLink;
            main = h_("WBHtml", {
                ref: "rawHtml",
                keyy: `wbhtml-key-${self.computedKey}-${el.length}`,
                props: { html: hasPipeFields ? el : el1 },
            });
            delegatedPipesToWBHtml = hasPipeFields;
        }
    }

    // Wrap in link if specified — skip when WBHtml already handles the link field.
    // Route the link through WBLink, which resolves it: `./`/`../` file refs and
    // existing named routes / paths become SPA navigation; external URLs and
    // in-page anchors fall back to a plain <a>.
    if (theFileLink && !delegatedPipesToWBHtml) {
        main = h_("WBLink", { props: { to: theFileLink, html: main } });
    }

    // Wrap in custom tag if parsedAs specified (non-standard types)
    if (parsedAs && !['css', 'js', 'python', 'php', 'rs', 'sh', 'md', 'html', 'tex', 'latex', 'vue', 'json', 'txt'].includes(parsedLower)) {
        main = h_(
            parsedAs || "pre",
            { ...classOrOptionsObj, ref: "rawHtml", title: el },
            [main]
        );
    }

    return main;
}
