/**
 * utils/dom.js
 * DOM manipulation, sanitization, and browser-related utilities
 */
import DOMPurify from 'dompurify';
import { objLang } from './data.js';
import { isEmpty } from './validation.js';

/**
 * Sanitize HTML string to prevent XSS attacks.
 * Always runs through DOMPurify for string inputs — no trusted bypass.
 */
export function sanitizeHtml(html) {
    if (typeof html !== 'string') return html;
    return DOMPurify.sanitize(html, { ADD_ATTR: ['target'] });
}

/**
 * Copy text to clipboard.
 */
export const copyToClipboard = function (text) {
    const textarea = document.createElement("textarea");
    textarea.value = text;
    document.body.appendChild(textarea);
    textarea.select();
    document.execCommand("copy");
    document.body.removeChild(textarea);
};

/**
 * Ultimate Vue 2 → Clean HTML converter.
 */
export function cleanVueHtml(html, options = {}) {
    const { removeEmpty = ['span', 'div', 'i', 'em'], collapseWrappers = ['span', 'div', 'i'], removeComments = true, trimWhitespace = true } = options;
    if (!html || typeof html !== 'string') return html;
    const container = document.createElement('div'); container.innerHTML = html;
    if (removeComments) {
        const walker = document.createTreeWalker(container, NodeFilter.SHOW_COMMENT);
        let node; while (node = walker.nextNode()) node.remove();
    }
    container.querySelectorAll('*').forEach(el => {
        el.getAttributeNames().filter(name => /^data-v-/.test(name)).forEach(name => el.removeAttribute(name));
    });
    const collapseSelector = collapseWrappers.join(',');
    let changed = true;
    while (changed) {
        changed = false;
        container.querySelectorAll(collapseSelector).forEach(el => {
            if (el.children.length === 1 && el.textContent.trim() === el.firstChild.textContent.trim() && !Array.from(el.attributes).some(attr => !/^data-v-/.test(attr.name))) {
                el.parentNode.insertBefore(el.firstChild, el); el.remove(); changed = true;
            }
        });
    }
    if (removeEmpty.length > 0) {
        container.querySelectorAll(removeEmpty.join(',')).forEach(el => {
            if (el.children.length === 0 && el.textContent.trim() === '' && !Array.from(el.attributes).some(attr => !/^data-v-/.test(attr.name))) el.remove();
        });
    }
    return container.innerHTML;
}

/**
 * Standard purification.
 */
export function purifyHtml(html) {
    return cleanVueHtml(html, { removeEmpty: ['span', 'div', 'i'], collapseWrappers: ['span', 'div', 'i'] });
}

/**
 * Clean minimal wrappers.
 */
export const cleanMinimal = (html) => cleanVueHtml(html, { removeEmpty: ['span', 'div'], collapseWrappers: ['span', 'div'] });

/**
 * Remove only empty spans.
 */
export const removeEmptySpans = (html) => cleanVueHtml(html, { removeEmpty: ['span'], collapseWrappers: ['span'] });

/**
 * Clean Vue VNodes.
 */
export function cleanVueVNode(vnode, h, options = {}) {
    const { removeEmpty = ['span', 'div'], collapseWrappers = ['span', 'div'] } = options;
    if (!vnode) return null;
    if (vnode.componentOptions) {
        if (vnode.children?.length) {
            const cleaned = vnode.children.map(c => cleanVueVNode(c, h, options)).filter(Boolean);
            if (cleaned.length === 0) return null;
            return h(vnode.componentOptions.Ctor, { ...vnode.data, props: vnode.componentOptions.propsData }, cleaned);
        }
        return vnode;
    }
    if (!vnode.tag) return vnode.text?.trim() ? vnode.text : null;
    const tag = vnode.tag.toLowerCase();
    const data = vnode.data || {};
    if (data.on || data.nativeOn || data.ref || data.directives || data.attrs || data.domProps || data.class || data.style) return recreate(vnode);
    if (collapseWrappers.includes(tag) && vnode.children?.length === 1 && !vnode.text?.trim()) return cleanVueVNode(vnode.children[0], h, options);
    if (removeEmpty.includes(tag) && !vnode.children?.length && !vnode.text?.trim()) return null;
    return recreate(vnode);
    function recreate(vnode) {
        const children = (vnode.children || []).map(c => cleanVueVNode(c, h, options)).filter(Boolean);
        if (children.length === 0 && !vnode.text?.trim()) return null;
        return h(vnode.tag, vnode.data, vnode.text?.trim() || children);
    }
}

/**
 * Data query logic using native fetch and localStorage.
 */
export function queryData({ obj_request, encFn = null, decFn = null, cacheName = null }) {
    if (!obj_request || Object.keys(obj_request).length === 0) return null;
    const { data, url, head, method = "get", actions = [] } = obj_request;

    let payload = data;
    if (encFn && typeof encFn === "function") payload = encFn(obj_request);

    // Transport: native fetch — NO vue-resource. Same contract the views are authored against:
    // request body `{ body: payload }`, host headers from `head`, and a `response.body` parsed
    // from the response TEXT (JSON when parseable, else the raw string — e.g. a JSON-quoted
    // "<hex>" → "<hex>"). The cached path returns `{ body }` so downstream actions read
    // `response.body` identically whether served from cache or the network.
    let promise;
    const cached = cacheName
        && localStorage.getItem(`${cacheName}_query`) == payload
        && localStorage.getItem(`${cacheName}_resp`);

    if (cached) {
        promise = Promise.resolve({ body: localStorage.getItem(`${cacheName}_resp`) });
    } else {
        promise = fetch(url, {
            method: method.toUpperCase(),
            headers: { "Content-Type": "application/json", ...(head || {}) },
            body: method.toLowerCase() !== "get" ? JSON.stringify({ body: payload }) : undefined,
        }).then(async (resp) => {
            const text = await resp.text();
            let body;
            try { body = JSON.parse(text); } catch { body = text; }
            return { body, status: resp.status, ok: resp.ok };
        });
        if (cacheName) {
            localStorage.setItem(`${cacheName}_query`, payload);
            promise.then((response) => localStorage.setItem(`${cacheName}_resp`, response.body));
        }
    }

    for (const aRespAction of actions) {
        promise = promise
            .then((response) => {
                // decFn returns the DECRYPTED string (or the raw body when absent); parse it
                // into `response.data` for the action.
                const decrypted = (decFn && typeof decFn === "function")
                    ? decFn(response, obj_request)
                    : response.body;
                try { response.data = JSON.parse(decrypted); }
                catch { response.data = decrypted; }
                return response;
            })
            .then(aRespAction?.[0])
            .catch((error) => Promise.reject(error))
            .catch(aRespAction?.[1]);
    }

    return promise;
}

/**
 * Set page meta parameters.
 */
export const setMetaParams = (viewMeta, lg = "en") => {
    const NAME_LIST = ["description", "keywords", "author", "viewport", "robots", "theme-color", "twitter:card", "twitter:site", "twitter:creator", "twitter:title", "twitter:description", "twitter:image"];
    const PROP_LIST = ["og:title", "og:type", "og:url", "og:image", "og:description", "og:site_name", "og:locale"];
    const FULL_LIST = [...NAME_LIST, ...PROP_LIST];
    if (viewMeta?.title) document.title = objLang(viewMeta.title, lg);
    if (viewMeta?.favIcon) {
        let href = objLang(viewMeta.favIcon, lg);
        let link = document.querySelector('link[rel="icon"]') || document.createElement("link");
        link.rel = "icon"; link.href = href; if (!link.parentNode) document.head.appendChild(link);
    }
    Object.entries(viewMeta || {}).forEach(([tag, val]) => {
        if (tag === "title" || tag === "favIcon" || !FULL_LIST.includes(tag)) return;
        let content = objLang(val, lg);
        let attrType = PROP_LIST.includes(tag) ? 'property' : 'name';
        let meta = document.querySelector(`meta[${attrType}='${tag}']`);
        if (meta) meta.content = content;
        else { meta = document.createElement("meta"); meta.setAttribute(attrType, tag); meta.content = content; document.head.appendChild(meta); }
    });
};

/**
 * Detect browser language.
 */
export const detectLang = (cookieKey = 'lg', fallback = 'en') => {
    try {
        const cookieMatch = document.cookie.match(new RegExp(`(?:^|; )${cookieKey}=([^;]*)`));
        if (cookieMatch) return decodeURIComponent(cookieMatch[1]);
        const browserLang = navigator.language || navigator.userLanguage;
        if (browserLang) return browserLang.split('-')[0];
    } catch { }
    return fallback;
};
