<script>
const normalize = (mod) => mod && (mod.default || mod);
import WBLink from "./WBLink.vue";
import JsonViewerImport from "vue-json-viewer";
const JsonViewer = normalize(JsonViewerImport);

import * as methodsObj from "../utils";

import MarkdownItImport from "markdown-it";
import markdownItAnchorImport from "markdown-it-anchor"; 
const MarkdownIt = normalize(MarkdownItImport);
const MarkdownItAnchor = normalize(markdownItAnchorImport);

if (markdownItAnchorImport.permalink && !MarkdownItAnchor.permalink) {
  MarkdownItAnchor.permalink = markdownItAnchorImport.permalink;
}

// Sentinel that brackets a base64-encoded WBC/component payload (see protectWbcPayloads).
// A control char (U+0001) so it can never collide with authored content, and is inert to
// every WBC tokenizer rule ([[ ]] {{ }} | __ ** -->) and to markdown-it.
const PAYLOAD_MARK = String.fromCharCode(1);
const PAYLOAD_RE = new RegExp(PAYLOAD_MARK + "([A-Za-z0-9+/=]*)" + PAYLOAD_MARK, "g");

const __DEV__ = typeof __WBC_DEV__ !== 'undefined'
    ? __WBC_DEV__
    : (typeof process !== 'undefined' && process.env
        ? process.env.NODE_ENV !== 'production'
        : false);

export default {
  name: "WBHtml",
  props: {
    /**
     * HTML content to render. Supports WBC's custom markup syntax including
     * [[component|styles|link]] patterns, {{wrapper}}content{{/wrapper}} syntax,
     * multilingual objects, and markdown. Can be a string, object, or array.
     * @type {string|object|array}
     * @default null
     */
    html: null,
  },

  // --- Eval trust boundary (security) ---
  // Inherit the ancestor WBC's "untrusted" verdict and re-provide it, so nested
  // WBC/WBHtml below an untrusted root keep evaluating in the AST sandbox. See
  // utils/security.js and the `untrusted` prop on WBC.
  inject: {
    wbcUntrustedInjected: { default: false },
  },
  provide() {
    return { wbcUntrustedInjected: this.wbcUntrustedInjected === true };
  },

  data() {
    return {
      viewMeta: null,
      html_: this.html || "",
      MarkdownIt: new MarkdownIt({
        html: true,
        linkify: true,
        typographer: true,
        breaks: false,
      }).use(MarkdownItAnchor, {
        permalink: MarkdownItAnchor.permalink.headerLink({
          safariReaderFix: true,
        }),
        slugify: (s) =>
          s
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, "-")
            .replace(/(^-|-$)/g, ""),
      }),
    };
  },

  render(h) {
    let wbhtmlToRender = this.mainRender(this.html_, h);
    if (typeof wbhtmlToRender == "string") {
      return h("span", { key: `${this.html_}` }, wbhtmlToRender);
    } else if (Array.isArray(wbhtmlToRender)) {
      return h("span", { key: `${this.html_}` }, [wbhtmlToRender]);
    } else {
      return this.mainRender(this.html_, h);
    }
  },

  methods: {
    mainRender(item, h) {
      try {
        return this._mainRender(item, h);
      } catch (e) {
        const sourceStr = typeof item === 'string' ? item : JSON.stringify(item);
        console.error(`-WBHtml Error-:\n[message]:${e.message}\n[error]:${e}\n[html]:${sourceStr}`);
        const sourceTrunc = sourceStr.length > 80 ? sourceStr.slice(0, 80) + '…' : sourceStr;
        return h('div', {
          style: {
            padding: '10px',
            margin: '10px',
            border: '1px solid #ff5252',
            borderRadius: '4px',
            backgroundColor: '#fff1f1',
            color: '#c62828',
            fontFamily: 'sans-serif',
            fontSize: '13px'
          }
        }, [
          h('div', { style: { fontWeight: 'bold', marginBottom: '5px' } }, `#WBHtmlError: ${e.message}`),
          h('div', { style: { fontSize: '12px', opacity: 0.85, marginTop: '4px', wordBreak: 'break-all' } }, `Source: ${sourceTrunc}`),
        ]);
      }
    },
    _mainRender(item, h) {
      // --- Object/array-content pipe forms — rendered THROUGH WBC so it applies its own
      // logic (generalVal/objLang localization, the <Comp,class> distributor, …). The
      // first check is on strToObj(<content>): a non-object/array keeps the existing
      // string-markup behavior (e.g. "li__hello|blue|x"). Shape is keyed by an optional
      // "<tag>__" wrapper prefix on segment 0 AND by whether the content is a LIST
      // (array or numeric-keyed object) or a LABELED object (e.g. a multilingual map):
      //
      //   (A) "<content>|<class_or_options>|<link>"           [labeled, no wrapper]
      //       {en:'Home',fr:'Acceuil',ar:'bayt'}|red|HomeView
      //       -> { options:{ html, class/…opts, to } }
      //
      //   (B) "<tag>__<content>|<featuresTag>__<featuresContentTag>|<link>"  [labeled + wrapper]
      //       div__{en:'Home',fr:'Acceuil'}|box__red|HomeView
      //       -> { comp:<tag>, options:{ …featuresTag, html:{ a:content,
      //                                    options:{ …featuresContentTag } }, to } }
      //
      //   (C) LIST content (array / numeric-keyed object) -> handed to WBC's distributor.
      //       With a wrapper tag we prepend WBC's `~` wrapper distributor so WBC builds
      //       <tag> as the SINGLE root with the distributed children directly inside it
      //       (no interposed element — which is what breaks container comps like VTabs).
      //       `featuresTag` styles the <tag> wrapper; `featuresContentTag` styles each
      //       item (an inner wrapper around its text/object); the content's own
      //       <Comp,class> distributor names the per-item element:
      //       VTabs__{0:'<VTab,green pa-2 ma-2>','1':'444','2':'aaa'}|red pa-2__pink pa-12|HomeView
      //       -> ['<~VTabs,red pa-2,HomeView>', '<VTab,green pa-2 ma-2>',
      //           {options:{html:'444',class:'pink pa-12'}}, {options:{html:'aaa',class:'pink pa-12'}}]
      //       (VTabs.red-pa-2 > 2 green VTab tabs, each wrapping its text in a .pink-pa-12 span.)
      //
      // The split is naive (per spec): an object literal containing a literal "|" isn't
      // supported. Limitation of (C): the wrapper's `featuresTag` must be a plain class
      // string (the distributor splits on ",").
      const pipeResult = this._parsePipeForm(item);
      if (pipeResult) return h("WBC", { props: { item: pipeResult } });
      // Fallthrough to legacy markup when pipe form didn't match.

      let el0 = this.objLang(item, this?.$store?.state?.lg);
      let el = this.styling(el0);

      if (!el) {
        return null;
      } else if (["string", "number", "boolean"].includes(typeof el)) {
        return h("span", {
          domProps: {
            innerHTML: this.sanitizeHtml(this.strToObj(el)),
            // innerHTML: this.strToObj(el),
          },
        }).children;
      } else if (Array.isArray(el)) {
        let finalOutputVn = [];

        el.forEach((el_) => {
          let outputVn = [];

          for (let aHtml of el_?.[1] || []) {
            let layout;
            let layoutWrap;
            // Handle case where aHtml might be a string instead of array (no pipe in content)
            let link = typeof aHtml === 'string' ? null : this.strToObj(aHtml?.[2]);
            let theHtml = typeof aHtml === 'string' ? aHtml : aHtml[0];

            let theWrap;

            // `~` is the shorthand alias for `WBC__` (e.g. `~./0.mp4`,
            // `~sdfsdfsd|red|aaaaaaaa`, `<!-- [[~{ comp:'meta' … }]] -->`). It MUST be
            // matched BEFORE the `__` wrap-split below: a WBC payload very often contains
            // `__` itself (`"__defineRoute"`, `__WBC_DEV__`, …), and the split would then
            // treat the leading `~{ …` chunk as the tag name, fail the tag-name regex, and
            // silently drop the WBC wrap — leaving the block to render as inert text.
            if (aHtml[0].trimStart().startsWith("~")) {
              theWrap = "WBC";
              theHtml = aHtml[0];
            } else if (aHtml[0].includes("__")) {
              let possibleWrap = aHtml[0].split("__")[0];
              if (/^[a-zA-Z][a-zA-Z0-9-]*$/.test(possibleWrap.trim())) {
                theWrap = possibleWrap;
                theHtml = aHtml[0].split("__").slice(1).join("__");
              } else {
                theHtml = aHtml[0];
              }
            }

            // Whitespace around delimiters ([[ li__x ]]) is cosmetic — strip it
            // from the tag so " li" doesn't get rejected as "Bad tag".
            if (theWrap) theWrap = theWrap.trim();

            // Reject tag names that document.createElement would refuse
            // (must start with a letter; only letters/digits/hyphens allowed).
            // Throw so the mainRender try/catch renders a visible error VNode
            // instead of letting Vue's patch phase crash on h(theWrap, ...).
            if (theWrap && theWrap !== "WBC" && theWrap !== "MD" && !/^[a-zA-Z][a-zA-Z0-9-]*$/.test(theWrap)) {
              throw new Error(`Bad tag "${theWrap}"`);
            }

            // Handle layout extraction based on whether aHtml is string or array
            if (typeof aHtml === 'string') {
              layoutWrap = {};
              layout = {};
            } else if (aHtml?.[1] && aHtml?.[1]?.includes("__")) {
              layoutWrap = this.strToObj(aHtml[1].split("__")?.[0]);
              layout = this.strToObj(aHtml[1].split("__").slice(1).join("__"));
            } else {
              layoutWrap = {};
              layout = this.strToObj(aHtml?.[1] || {});
            }

            if (typeof layout == "string") {
              layout = { class: layout };
            }
            if (typeof layoutWrap == "string") {
              layoutWrap = { class: layoutWrap };
            }

            if (["", "null", "undefined"].includes(typeof aHtml === 'string' ? aHtml : aHtml[0])) {
              return h("div", {}, ["null"]);
            } else {
              let theOutputVn;

              if (typeof theHtml == "string" && theHtml?.startsWith("./")) {
                theWrap = "WBC";
              } else if (theWrap == "MD" && typeof theHtml == "string") {
                theHtml = this.MarkdownIt.render(theHtml);
              }

              if (this.isNonEmpty(link)) {
                theOutputVn = h("WBLink", {
                  ...(theWrap == "MD"
                    ? {
                        ...layout,
                        class: "markdown-body " + (layout?.class || ""),
                      }
                    : layout),

                  props: {
                    to: this.strToObj(aHtml[2]),
                    html: theHtml,
                    style_: {},
                    attrs_: {},
                  },
                });
              } else {
                if (theWrap == "WBC") {
                    // Handled by specific WBC component logic below
                } else if (layout) {
                  theOutputVn = h("span", {
                    ...layout,
                    domProps: {
                      innerHTML: this.sanitizeHtml(this.objLang(
                        this.strToObj(theHtml),
                        this?.$store?.state?.lg
                      )),
                    },
                  });
                } else {
                  theOutputVn = this.objLang(
                    this.strToObj(theHtml),
                    this?.$store?.state?.lg
                  );
                }
              }

              if (theWrap) {
                if (theWrap == "tex" || theWrap == "latex" || `${theWrap}`.toLowerCase() == "latex") {
                  let theTex;
                  if (theWrap == "tex") {
                    theTex = [
                      h("WBLatex", {
                        ...layout,
                        props: {
                          expression: theHtml,
                        },
                      }),
                    ];
                  } else {
                    theTex = this.parseTexFile(theHtml || "").map((block) => {
                      if (block.type === "text") {
                        return h("div", [
                          h("WBHtml", {
                            props: {
                              html: block.content + " ",
                            },
                          }),
                        ]);
                      }

                      if (block.type === "math") {
                        return h("WBLatex", {
                          props: {
                            expression: block.expression,
                            "display-mode": block.displayMode ?? false,
                          },
                        });
                      }

                      if (block.type === "mixed") {
                        return h(
                          "div",
                          { class: "d-inline-flex align-center" },
                          block.lineContent.map((part) => {
                            if (part.expression) {
                              return h("WBLatex", {
                                props: {
                                  expression: part.expression,
                                  "display-mode": false,
                                },
                              });
                            }
                            return h("WBHtml", {
                              props: { html: " " + part.content + " " },
                            });
                          })
                        );
                      }
                    });
                  }

                  let texObj = h(
                    "span",
                    {
                      ...layoutWrap,
                    },
                    theTex
                  );

                  if (this.isNonEmpty(link)) {
                    texObj = h("WBLink", {
                      props: {
                        to: this.strToObj(aHtml[2]),
                        html: texObj,
                        style_: {},
                        attrs_: {},
                      },
                    });
                  }
                  outputVn.push(texObj);
                } else if (theWrap == "WBC") {
                  // Strip the optional `~` alias marker (plus any cosmetic leading
                  // whitespace) before parsing, mirroring the trimStart() detection above.
                  const wbcSrc = theHtml.trimStart().startsWith("~")
                    ? theHtml.trimStart().slice(1)
                    : theHtml;
                  let theHtmlBase = this.strToObj(wbcSrc);

                  outputVn.push(
                    h("WBC", {
                      props: { item: theHtmlBase },
                    })
                  );
                } else if (theHtml.startsWith("~")) {
                    outputVn.push(
                      h(theWrap, {
                        props: this.strToObj(theHtml.slice(1)),
                      })
                    );
                } else {
                  outputVn.push(
                    h(
                      theWrap == "MD"
                        ? "div"
                        : this.charCoding(theWrap, [
                            ["&vert;", "\\|"],
                            ["&#95;&#95;", "__"],
                            ["\\", ""],
                            ["&lbrack;", "["],
                            ["&rbrack;", "]"],
                            ["&lbrace;", "{"],
                            ["&rbrace;", "}"],
                            ["&lpar;", "("],
                            ["&rpar;", ")"],
                            ["&lt;", "<"],
                            ["&gt;", ">"],
                          ]),
                      {
                        ...(theWrap == "MD"
                          ? {
                              ...layout,
                              class: "markdown-body " + (layout?.class || ""),
                            }
                          : {}),
                        ...layoutWrap,
                      },
                      [theOutputVn]
                    )
                  );
                }
              } else {
                outputVn.push(theOutputVn);
              }
            }
          }

          let wrapTag = "span",
            wrapOptions = {},
            wrapLink = null;
          if (typeof el_[0] == "string") {
            [wrapTag, wrapOptions, wrapLink] = el_[0].split("|");
          }

          // Same hygiene as the inner tag: trim cosmetic whitespace, reject
          // anything document.createElement would refuse.
          if (typeof wrapTag === "string") wrapTag = wrapTag.trim();
          if (wrapTag && wrapTag !== "WBC" && wrapTag !== "MD" && !/^[a-zA-Z][a-zA-Z0-9-]*$/.test(wrapTag)) {
            throw new Error(`Bad tag "${wrapTag}"`);
          }

          let wrapOptionsObj = this.strToObj(wrapOptions);
          if (typeof wrapOptionsObj == "string") {
            wrapOptionsObj = {
              class: wrapOptionsObj,
            };
          }
          if (wrapLink) {
            outputVn = h("WBLink", {
              props: {
                to: this.strToObj(wrapLink),
                html: outputVn,
                style_: {},
                attrs_: {},
              },
            });
          }
          let thewrapVn = h(wrapTag, { ...wrapOptionsObj }, [outputVn]);
          finalOutputVn.push(thewrapVn);
        });
        return finalOutputVn;
      } else if (typeof el == "object") {
        let ele = this.objLang(el, this?.$store?.state?.lg);
        return this.mainRender(this.styling(ele), h);
      }
    },
    styling(el) {
      let el_ = el;
      if (typeof el !== "string") return `${JSON.stringify(el)}`;
      if (typeof el == "string" && el.indexOf("[[") == 0) {
        el = "{{span}}" + el;
      }

      // Skip auto-wrapping when the input is already a complete WBC markup:
      //   - starts with `{{` (has explicit wrapper), or
      //   - already ends with `]]` (has closing bracket).
      // The previous check used `!= "]]"` against a single char, which always
      // matched and caused double-wrapping of well-formed input like
      // `{{ol}}[[li__x]][[li__y]]` — that broke the inner-tag split.
      if (
        typeof el == "string" &&
        el.indexOf("[[") != 0 &&
        !el.startsWith("{{") &&
        el.slice(-2) !== "]]"
      ) {
        el = "{{span}}[[" + el + "]]";
      }
      if (
        typeof el == "string" &&
        (el.includes("[[") ||
          el.includes("]]") ||
          el.includes("|") ||
          el.includes("{{") ||
          el.includes("}}")) &&
        (el[0] != "{" || el[el.length - 1] != "}")
      ) {
        el_ = el
          .split("{{")
          .filter((eee) => !!eee)
          .map((ee) =>
            ee.split("}}").map((ee) => {
              if (!(ee.includes("[[") || ee.includes("]]"))) {
                return ee;
              }
              return ee
                .replace(/\[\[/g, "**")
                .replace(/\]\]/g, "**")
                .split("**")
                .filter((eee) => !!eee)
                .map((h) => h.split("|"));
            })
          );
      }
      return this.strToObj(el_);
    },
    charCoding(s, arr) {
      if (typeof s !== "string") return s;
      arr.forEach((rule) => {
        const [car, repl] = rule;
        s = s.split(car).join(repl);
      });
      return s;
    },
    // Verbatim/raw-text regions (code-display panels, <script>/<style> examples, and the
    // copy-button's data-clipboard-text attribute) often contain WBC syntax being *documented*
    // — literal [[ ]] {{ }} __ | sequences. Those must NOT drive WBC's markup tokenization,
    // or the bracket/`**` pairing in styling() mis-aligns and a chunk of surrounding HTML is
    // parsed as a tag ("Bad tag"). Encode ONLY the tokenizer's marker *sequences* to entities:
    // they render as the exact same glyphs but are inert to the tokenizer. Single { [ _ are
    // left intact so real CSS/code (and legit single-char content) is untouched.
    // `*` is encoded too: styling() converts [[ ]] → `**` and SPLITS on `**`, so a literal
    // `**` in a fence (e.g. a glob `'./content/**/*.md'`) injects a phantom split boundary
    // that mis-pairs the surrounding brackets and truncates the block. `&#42;` renders as the
    // exact same glyph but carries no `**` for the splitter to trip on.
    protectCodeRegions(s) {
      if (typeof s !== "string" || s.indexOf("<") === -1) return s;
      const encode = (frag) =>
        frag
          .split("[[").join("&lbrack;&lbrack;")
          .split("]]").join("&rbrack;&rbrack;")
          .split("{{").join("&lbrace;&lbrace;")
          .split("}}").join("&rbrace;&rbrace;")
          .split("__").join("&#95;&#95;")
          .split("*").join("&#42;")
          .split("|").join("&vert;");
      return s
        // Raw-text element bodies: their content is literal, never WBC markup.
        .replace(/<(pre|code|script|style|textarea)\b[\s\S]*?<\/\1>/gi, encode)
        // Copy-button payload: data-clipboard-text="…" carries the raw source verbatim.
        .replace(/data-clipboard-text="[^"]*"/gi, encode);
    },
    // ── WBC / general-component PAYLOAD protection ──────────────────────────────────
    // A WBC alias (`~{…}` / `~[…]`) or component-object payload (`WBC__{…}`, `Comp__~{…}`)
    // is an arbitrary JS object/array literal. Its braces, brackets, pipes and quotes collide
    // head-on with the WBC tokenizer (styling() splits on `{{` `}}` `[[` `]]` `|`; created()'s
    // charCoding rewrites `}}}`→`} }}` etc.) AND, for the bare (non-comment) form, markdown-it
    // has already smart-quoted (`'`→`’`) and HTML-escaped (`"`→`&quot;`) the source. Either way a
    // deeply-nested payload (`…{c13:{c131:131}}}}`) is shredded before strToObj ever sees it.
    //
    // Fix: lift each payload OUT of the tokenizer's reach. Balanced-scan the literal, normalize
    // its quotes back to straight ASCII, base64-encode it (base64's alphabet shares no character
    // with any tokenizer marker), and leave `MARK<base64>MARK` in its place. The `~`/`WBC__`/`__`
    // prefix is preserved so existing routing still recognises the block; the inert blob is then
    // decoded back to source at the strToObj parse boundary (and in display paths, as a fallback).
    protectWbcPayloads(s) {
      if (typeof s !== "string") return s;
      // Triggers: `~` or `WBC__` immediately followed by an object/array literal. After
      // protectCodeRegions, documented payloads inside <code> have their `{`/`~` entity-encoded,
      // so they no longer match here — only LIVE payloads are protected.
      const triggerRe = /(?:~|WBC__)(\{|\[)/g;
      let out = "", last = 0, m;
      while ((m = triggerRe.exec(s))) {
        const openIdx = m.index + m[0].length - 1; // index of the `{` or `[`
        const end = this._scanBalancedPayload(s, openIdx);
        if (end === -1) continue; // unbalanced — leave as-is
        const raw = this._normalizePayloadQuotes(s.slice(openIdx, end));
        out += s.slice(last, openIdx) + PAYLOAD_MARK + this._encodePayload(raw) + PAYLOAD_MARK;
        last = end;
        triggerRe.lastIndex = end; // resume scanning AFTER the payload we just consumed
      }
      return last === 0 ? s : out + s.slice(last);
    },
    // Decode any `MARK<base64>MARK` blobs back to their raw payload source.
    unprotectWbcPayloads(s) {
      if (typeof s !== "string" || s.indexOf(PAYLOAD_MARK) === -1) return s;
      return s.replace(PAYLOAD_RE, (_, b64) => this._decodePayload(b64));
    },
    // Balanced scan from an opening `{`/`[`, returning the index AFTER its matching close (or -1).
    // String literals (incl. markdown-it's curly-quote pairs) are skipped so braces inside strings
    // never throw off the depth count.
    _scanBalancedPayload(s, openIdx) {
      const openers = { "'": "'", '"': '"', "`": "`", "‘": "’", "“": "”" };
      let depth = 0, str = null;
      for (let i = openIdx; i < s.length; i++) {
        const c = s[i];
        if (str) {
          if (c === "\\") { i++; continue; }
          if (c === str) str = null;
          continue;
        }
        if (openers[c]) { str = openers[c]; continue; }
        if (c === "{" || c === "[") depth++;
        else if (c === "}" || c === "]") { if (--depth === 0) return i + 1; }
      }
      return -1;
    },
    // Reverse markdown-it's typographic + HTML-entity mangling so the lifted payload is valid JS.
    _normalizePayloadQuotes(s) {
      return s
        .replace(/[‘’‚‛]/g, "'")
        .replace(/[“”„‟]/g, '"')
        .replace(/&quot;/g, '"')
        .replace(/&apos;/g, "'")
        .replace(/&#0*39;/g, "'")
        .replace(/&#x0*27;/gi, "'")
        .replace(/&lt;/g, "<")
        .replace(/&gt;/g, ">")
        .replace(/&amp;/g, "&"); // ampersand LAST so it can't re-form the entities above
    },
    _encodePayload(s) {
      try { return btoa(unescape(encodeURIComponent(s))); }
      catch (e) { try { return btoa(s); } catch (e2) { return s; } }
    },
    _decodePayload(b64) {
      try { return decodeURIComponent(escape(atob(b64))); }
      catch (e) { try { return atob(b64); } catch (e2) { return b64; } }
    },
    // ── Dev-only shorthand explainer ───────────────────────────────────────────
    // Exposes the WBC item a shorthand string compiles to, for debugging. Only
    // available in dev builds (__WBC_DEV__). Returns null when the input is not a
    // pipe-form shorthand (legacy string markup returns null — use the component's
    // own render output to debug that path).
    explainShorthand(input) {
      if (!__DEV__) return null;
      if (typeof input !== "string") return null;
      try {
        let s = this.protectWbcPayloads(input);
        s = this.charCoding(s, [
          ["\\|", "&vert;"],
          ["\\__", "&#95;&#95;"],
          ["\\{", "&lbrace;"], ["\\}", "&rbrace;"],
          ["\\[", "&lbrack;"], ["\\]", "&rbrack;"],
          ["\\(", "&lpar;"], ["\\)", "&rpar;"],
          ["\\<", "&lt;"], ["\\>", "&gt;"],
        ]);
        return this._parsePipeForm(s, { diagnostics: true });
      } catch (e) {
        return { _error: e.message };
      }
    },
    // ── Pipe-form parser (internal) ────────────────────────────────────────────
    // Parses a pipe-delimited shorthand string into the WBC item it would produce.
    // Returns the compiled item (object/array) when the input matches the pipe form,
    // or null when the input is legacy string markup (falls through to styling()).
    // Throws descriptive errors on malformed input when `opts.diagnostics` is true.
    //
    // Split on ROOT-level pipes only. Pipes inside the content's array/object literal
    // (or inside quotes) belong to the inner items' own `text|class|link` markup and
    // MUST be preserved — e.g. VTabs__['44444|blue|link', …]|red__pink|HomeView has 3
    // root segments, not 5. Walk left→right tracking [ ] { } ( ) depth + quote state.
    _splitTopLevel(str, splitOpts) {
      const parts = [];
      let depth = 0, quote = null, buf = "";
      for (let k = 0; k < str.length; k++) {
        const c = str[k];
        if (quote) {
          buf += c;
          if (c === quote && str[k - 1] !== "\\") quote = null;
        } else if (c === "'" || c === '"' || c === "`") {
          quote = c; buf += c;
        } else if (c === "[" || c === "{" || c === "(") {
          depth++; buf += c;
        } else if (c === "]" || c === "}" || c === ")") {
          depth--; buf += c;
        } else if (c === "|" && depth === 0) {
          if (buf === "" && parts.length === 0) {
            if (splitOpts?.diagnostics) throw new Error("Pipe form segment 0 is empty");
          }
          parts.push(buf); buf = "";
        } else {
          buf += c;
        }
      }
      if (buf === "" && parts.length > 0) {
        if (splitOpts?.diagnostics) throw new Error("Pipe form ends with an empty segment");
      }
      parts.push(buf);
      return parts;
    },
    _parsePipeForm(item, opts) {
      if (typeof item !== "string" || !item.includes("|")) return null;
      const diag = opts?.diagnostics === true;
      const htmlArr = this._splitTopLevel(item, opts);
      if (htmlArr.length < 1) return null;

      // Optional "<tag>__" prefix on segment 0 (tag must be a valid element/comp name).
      let tag = null;
      let contentRaw = htmlArr[0];
      if (htmlArr[0].includes("__")) {
        const i = htmlArr[0].indexOf("__");
        const maybeTag = htmlArr[0].slice(0, i).trim();
        if (/^[a-zA-Z][a-zA-Z0-9-]*$/.test(maybeTag)) {
          tag = maybeTag;
          contentRaw = htmlArr[0].slice(i + 2);
        }
      }

      // Legacy `[[ ... ]]` markup is NOT a pipe form, even though safeEval can
      // parse `[[content]]` as a JS array literal. If segment 0 starts with `[[`,
      // skip pipe-form detection and fall through to the styling() path.
      if (contentRaw.trimStart().startsWith("[[")) return null;

      const htmlObj = this.strToObj(contentRaw);
      if (!htmlObj || typeof htmlObj !== "object") return null;

      if (diag) {
        // Validate each segment is parseable when diagnostics are requested.
        if (htmlArr.length > 1 && htmlArr[1] !== "") {
          const seg1Parsed = this.strToObj(htmlArr[1]);
          if (seg1Parsed === undefined) {
            throw new Error(`Pipe segment 1 didn't parse as a WBC style/options: "${htmlArr[1]}"`);
          }
        }
        if (htmlArr.length > 2) {
          const linkRaw = htmlArr.slice(2).join("|");
          if (linkRaw) {
            const linkParsed = this.strToObj(linkRaw);
            if (linkParsed === undefined) {
              throw new Error(`Pipe segment 2 (link) didn't parse: "${linkRaw}"`);
            }
          }
        }
      }

      const isArray = Array.isArray(htmlObj);
      const keys = isArray ? [] : Object.keys(htmlObj);
      const isList = isArray || (keys.length > 0 && keys.every((k) => /^\d+$/.test(k)));

      // text segment -> `class`; object segment -> spread into the options.
      const applyStyle = (opts, seg) => {
        const s = (seg === undefined || seg === "") ? undefined : this.strToObj(seg);
        if (s && typeof s === "object" && !Array.isArray(s)) Object.assign(opts, s);
        else if (this.isNonEmpty(s)) opts.class = s;
        return opts;
      };

      // Segment 1 -> wrapper (featuresTag) + content (featuresContentTag) styling.
      const seg1 = htmlArr.length > 1 ? htmlArr[1] : "";
      let featuresSeg = seg1, featuresContentSeg = "";
      if (seg1.includes("__")) {
        const j = seg1.indexOf("__");
        featuresSeg = seg1.slice(0, j);
        featuresContentSeg = seg1.slice(j + 2);
      }

      // Segment 2+: link/route.
      const linkRaw = htmlArr.length > 2 ? htmlArr.slice(2).join("|") : "";
      const linkSeg = linkRaw ? this.strToObj(linkRaw) : undefined;

      if (isList) {
        let items = isArray
          ? htmlObj.slice()
          : keys.sort((a, b) => a - b).map((k) => htmlObj[k]);

        const fcStyle = featuresContentSeg && featuresContentSeg.trim() ? featuresContentSeg : "";
        if (fcStyle) {
          items = items.map((it) =>
            (typeof it === "string" && it.startsWith("<") && it.endsWith(">"))
              ? it
              : { options: applyStyle({ html: it }, fcStyle) }
          );
        }

        let result = items;
        if (tag) {
          const wrapper = "<~" + tag + "," + (featuresSeg || "") +
            (this.isNonEmpty(linkSeg) ? "," + linkRaw : "") + ">";
          result = [wrapper, ...items];
        }
        return result;
      }

      let newHtmlObj;
      if (tag) {
        newHtmlObj = {
          comp: tag,
          options: {
            ...applyStyle({}, featuresSeg),
            html: { a: htmlObj, options: applyStyle({}, featuresContentSeg) },
          },
        };
        if (this.isNonEmpty(linkSeg)) newHtmlObj.options.to = linkSeg;
      } else {
        const options = applyStyle({ html: htmlObj }, htmlArr.length > 1 ? htmlArr[1] : undefined);
        if (this.isNonEmpty(linkSeg)) options.to = linkSeg;
        newHtmlObj = { options };
      }
      return newHtmlObj;
    },
    ...Object.fromEntries(
            Object.entries(methodsObj).filter(
                ([key, value]) => typeof value === "function"
            )
        ),
    // Trust-aware override of the spread `strToObj` (defined AFTER the spread so it wins).
    // Forces the AST sandbox for url-supplied / untrusted subtrees.
    strToObj(input, opts) {
      // Restore any protected WBC/component payload to its raw source right before parsing
      // (see protectWbcPayloads). Cheap guard: the sentinel is a single control char.
      if (typeof input === "string" && input.indexOf(PAYLOAD_MARK) !== -1) {
        input = this.unprotectWbcPayloads(input);
      }
      const untrusted = this.wbcUntrustedInjected === true;
      return methodsObj.strToObj(input, { trusted: !untrusted, ...(opts || {}) });
    },
  },

  components: {
    JsonViewer: JsonViewer,
    WBLink,
  },
  
  created() {
    // Un-wrap ANY WBC block authored inside an HTML comment — the
    // `<!-- [[ ... ]] -->` convention (incl. the per-view `<!-- [[~{ comp:'meta' ... }]] -->`).
    // Authors wrap live demos in a comment so the raw Markdown source stays clean: a bare
    // `[[ ... ]]` renders as literal text in plain Markdown viewers / GitHub, whereas the
    // commented form is invisible there but mounts as a real WBC component here. Expose the
    // inner `[[ ... ]]` so it renders. This MUST run before the generic `-->`→"" rewrite
    // below, which strips only the closer and would otherwise leave a dangling `<!--` that
    // derails the tokenizer ("Bad tag") and drops the block entirely.
    // The match is non-greedy AND anchored on `\s*-->`, so each `[[` pairs with the `]]`
    // that precedes its own `-->` — nested `]]` inside the block don't close it early.
    if (typeof this.html_ === "string") {
      this.html_ = this.html_.replace(
        /<!--\s*(\[\[[\s\S]*?\]\])\s*-->/g,
        "$1"
      );
    }
    // Neutralize WBC markers inside code-display regions before the markup rewrites below,
    // so documented syntax (literal [[ ]] __ |) can't corrupt the tokenizer's bracket pairing.
    this.html_ = this.protectCodeRegions(this.html_);
    // Lift live WBC/component payloads (`~{…}`, `WBC__{…}`, `Comp__~{…}`) out of the tokenizer's
    // reach BEFORE the brace/bracket rewrites below shred their nested literals. Runs AFTER
    // protectCodeRegions (so documented payloads inside <code> are already entity-shielded and
    // won't be matched) and AFTER comment-unwrap (so commented blocks are protected too).
    this.html_ = this.protectWbcPayloads(this.html_);
    this.html_ = this.charCoding(this.html_, [
      ["<p>", "<p>[["],
      ["<\/p>", "]]<\/p>"],
      ["\\|", "&vert;"],
      ["\\__", "&#95;&#95;"],
      ["\\{", "&lbrace;"],
      ["\\}", "&rbrace;"],
      ["\\[", "&lbrack;"],
      ["\\]", "&rbrack;"],
      ["\\(", "&lpar;"],
      ["\\)", "&rpar;"],
      ["\\<", "&lt;"],
      ["\\>", "&gt;"],
      ["-->", ""],
      ["]]]", "] ]]"],
      ["[[[", "[[ ["],
      ["}}}", "} }}"],
      ["{{{", "{{ {"],
    ]);
  },
};
</script>
