/**
 * utils/validation.js
 * Type checks, semantical checks, and standard validators
 */

/**
 * Detect if an object is a Vue VNode.
 */
export const isVnode = function (x) {
    return (
        typeof x === "object" &&
        x !== null &&
        x.hasOwnProperty("context") &&
        x.hasOwnProperty("tag")
    );
};

/**
 * Check if a string is a valid ISO date.
 */
export const isDate = function (d) {
    if (typeof d !== 'string') return false;
    const regex = /^\d{4}-\d{2}-\d{2}$/;
    if (d.match(regex) === null) return false;
    const date = new Date(d);
    const timestamp = date.getTime();
    if (typeof timestamp !== "number" || Number.isNaN(timestamp)) return false;
    return date.toISOString().startsWith(d);
};

/**
 * Determines if a value is semantically empty.
 */
export function isEmpty(value) {
    return (
        value == null ||
        (Array.isArray(value) && value.length === 0) ||
        (typeof value === "object" && Object.keys(value).length === 0) ||
        (typeof value === "string" && value.trim() === "") ||
        (value instanceof Set && value.size === 0)
    );
}

/**
 * Inverse of isEmpty.
 */
export function isNonEmpty(value) {
    return !isEmpty(value);
}

/**
 * Check if a value is a plain object (not array, not function).
 */
export function isPlainObject(variable) {
    return (
        typeof variable === "object" &&
        !Array.isArray(variable) &&
        variable !== null &&
        !(variable instanceof Function)
    );
}

/**
 * Check if an object is iterable.
 */
export const isIterable = function (obj) {
    if (obj == null) return false;
    return typeof obj[Symbol.iterator] === "function";
};

/**
 * Detect if a function is a dynamic import or returns a Promise.
 */
export function isDynamicImport(value) {
    if (typeof value === "function") {
        try {
            const result = value();
            return isPromise(result);
        } catch (error) { return false; }
    }
    return false;
}

/**
 * Detect if a value is a Promise or Thenable.
 */
export function isPromise(value) {
    return (
        value &&
        typeof value === "object" &&
        typeof value.then === "function" &&
        typeof value.catch === "function"
    );
}

/**
 * Check if any element in `toMatch` exists in `target`.
 */
export const anyMatchInArray = function (target, toMatch) {
    if (!Array.isArray(target) || !Array.isArray(toMatch)) return false;
    const targetSet = new Set(target);
    return toMatch.some(item => targetSet.has(item));
};

/**
 * Count occurrences of a substring.
 */
export function countStr(s, substring) {
    if (!substring || typeof s !== 'string') return 0;
    const regex = new RegExp(substring.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g');
    const matches = s.match(regex);
    return matches ? matches.length : 0;
}

/**
 * Standard validators for forms and inputs.
 */
export const validators = {
    required(v, o = {}) {
        o.lg ??= "en";
        o.message ??= { en: "This field is required.", fr: "Ce champ est requis.", ar: "هذه الخانة مطلوبه." };
        return (v && v.length != 0) || o.message?.[o.lg] || JSON.stringify(o.message);
    },
    banned(v, o = {}) {
        o.lg ??= "en";
        o.message ??= { en: `"${v}" is banned`, fr: `"${v}" est interdite`, ar: `"${v}" محظور` };
        if (Array.isArray(o.banned)) return !o.banned.includes(v) || o.message?.[o.lg] || JSON.stringify(o.message);
        else if (typeof o.banned == "string") return o.banned != v || o.message?.[o.lg] || JSON.stringify(o.message);
        else return true;
    },
    includes(v, o = {}) {
        o.lg ??= "en";
        o.message ??= { en: `"${v}" does not contain "${o.containingValues}"`, fr: `"${v}" ne contient pas "${o.containingValues}"`, ar: `"${v}" لا يحتوي على "${o.containingValues}"` };
        if (Array.isArray(o.containingValues)) return o.containingValues.every((e) => v.includes(e)) || o.message?.[o.lg] || JSON.stringify(o.message);
        else if (typeof o.containingValues == "string") return (v && v.includes(o.containingValues)) || o.message?.[o.lg] || JSON.stringify(o.message);
        else return true;
    },
    excludes(v, o = {}) {
        o.lg ??= "en";
        o.message ??= { en: `"${v}" must not contain "${o.containingValues}"`, fr: `"${v}" ne doivent pas contenir "${o.containingValues}"`, ar: `"${v}" يجب ألا تحتوي "${o.containingValues}"` };
        if (Array.isArray(o.containingValues)) return o.containingValues.every((e) => !v.includes(e)) || o.message?.[o.lg] || JSON.stringify(o.message);
        else if (typeof o.containingValues == "string") return !v.includes(o.containingValues) || o.message?.[o.lg] || JSON.stringify(o.message);
        else return true;
    },
    username(v, o = {}) {
        o.lg ??= "en";
        o.message ??= { en: "Only letters, numbers and underscore are allowed.", fr: "Chiffres et soulignement autorisés", ar: "فقط الحروف والأرقام والأحرف السفلية مسموح بها" };
        return /^[a-zA-Z0-9_]+$/.test(v) || o.message?.[o.lg] || JSON.stringify(o.message);
    },
    maxLength(v, o = {}) {
        o.len ??= 25; o.lg ??= "en"; o.message ??= { en: `Max ${o.len} characters allowed.`, fr: `Au maximum ${o.len} caractères sont autorisés.`, ar: `الحد الأقصى المسموح به من الأحرف ${o.len}.` };
        return (v && v.length <= o.len) || o.message?.[o.lg] || JSON.stringify(o.message);
    },
    minLength(v, o = {}) {
        o.len ??= 4; o.lg ??= "en"; o.message ??= { en: `Min ${o.len} characters allowed.`, fr: `Au minimum ${o.len} caractères sont autorisés.`, ar: `الحد الأدنى المسموح به من الأحرف ${o.len}.` };
        return (v && v.length >= o.len) || o.message?.[o.lg] || JSON.stringify(o.message);
    },
    upperCharNb(v, o = {}) {
        o.len ??= 1; o.lg ??= "en";
        o.message ??= { en: `At least ${o.len} Uppercase letter is needed.`, fr: `Au moins ${o.len} lettre majuscule.`, ar: `مطلوب على الأقل ${o.len} حرف كبير.` };
        if (v) {
            const up = JSON.stringify(v).match(/[A-Z]/g);
            return (up && up.length >= o.len) || o.message?.[o.lg] || JSON.stringify(o.message);
        } return true;
    },
    lowerCharNb(v, o = {}) {
        o.len ??= 1; o.lg ??= "en";
        o.message ??= { en: `At least ${o.len} lowercase letter is needed.`, fr: `Au moins ${o.len} lettre minuscule.`, ar: `مطلوب على الأقل ${o.len} حرف صغير.` };
        if (v) {
            const low = JSON.stringify(v).match(/[a-z]/g);
            return (low && low.length >= o.len) || o.message?.[o.lg] || JSON.stringify(o.message);
        } return true;
    },
    specialCharNb(v, o = {}) {
        o.len ??= 1; o.lg ??= "en";
        o.message ??= { en: `At least ${o.len} special characters is needed.`, fr: `Au moins ${o.len} caractère spécial.`, ar: `مطلوب ما لا يقل عن ${o.len} حرف خاص` };
        if (v) {
            const spec = JSON.stringify(v).match(/[@#$%^&*()_+\-=[\]{}!`;':"\\|,.<>/?]/g);
            return (spec && spec.length - 2 >= o.len) || o.message?.[o.lg] || JSON.stringify(o.message);
        } return true;
    },
    digitCharNb(v, o = {}) {
        o.len ??= 1; o.lg ??= "en";
        o.message ??= { en: `At least ${o.len} digit is needed.`, fr: `Au moins ${o.len} chiffre.`, ar: `مطلوب ما لا يقل عن ${o.len} رقم.` };
        if (v) {
            const dig = JSON.stringify(v).match(/[1-9]/g);
            return (dig && dig.length >= o.len) || o.message?.[o.lg] || JSON.stringify(o.message);
        } return true;
    },
    isValidDate(v, o = {}) {
        o.lg ??= "en"; o.message ??= { en: `"${v}" is not a valid date.`, fr: `"${v}" n'est pas une date valide`, ar: `"${v}" ليس تاريخًا صالحًا.` };
        if (!/^\d\d\d\d-\d\d\-\d\d$/.test(v)) return o.message?.[o.lg] || JSON.stringify(o.message);
        const parts = v.split("-").map((p) => parseInt(p, 10));
        const d = new Date(parts[0], parts[1] - 1, parts[2]);
        const cond = d.getMonth() === parts[1] - 1 && d.getDate() === parts[2] && d.getFullYear() === parts[0];
        return cond || o.message?.[o.lg] || JSON.stringify(o.message);
    },
    email(v, o = {}) {
        o.lg ??= "en"; o.message ??= { en: `"${v}" Invalid format.`, fr: `Format non valide.`, ar: `شكل غير صالح.` };
        return /^\w+([.\-+]?\w+)*\+*@\w+([.-]?\w+)*(\.\w{2,24})+$/.test(v) || o.message?.[o.lg] || JSON.stringify(o.message);
    },
    phone(v, o = {}) {
        o.lg ??= "en"; o.message ??= { en: `"${v}" Invalid format.`, fr: `Format non valide.`, ar: `تنسيق غير صالح.` };
        return /^[+]?[(]?[0-9]{3}[)]?[-\s.]?[0-9]{3}[-\s.]?[0-9]{4,6}$/im.test(v) || o.message?.[o.lg] || JSON.stringify(o.message);
    }
};
