/**
 * Rendering helpers for media and file types in WBC.
 *
 * All helpers are exported as pure functions: the Vue component instance
 * (`self` / `ctx`) is passed explicitly as the last parameter. When spread
 * into Vue methods:{} the functions still work via `this` fallback.
 */

/**
 * Check if file matches any extension in array
 * @param {string} filename - Filename to check
 * @param {string[]} extensions - Array of extensions to match
 */
export const _matchesFileType = (filename, extensions) => {
    if (!filename || !extensions) return false;
    const clean = filename.split('?')[0].split('#')[0].toLowerCase();
    return extensions.some(ext => clean.endsWith(ext.toLowerCase()));
};

/**
 * Determine path type (local/served/online/text)
 * @param {string} path - Path string to analyze
 */
export const _getPathType = (path) => {
    if (path.startsWith('http://') || path.startsWith('https://')) return 'online';
    if (path.startsWith('/')) return 'served';
    if (path.startsWith('./') || path.startsWith('../')) return 'local';
    return 'text';
};

/**
 * Helper: Render image element
 */
export const _renderImage = (h_, src, classOrOptionsObj = {}) => {
    const imgObj = {
        attrs: { title: src, src },
        class: 'container',
        ref: 'rawHtml',
        ...classOrOptionsObj,
    };
    if (src.includes('.ico')) imgObj.attrs.alt = 'Icon';
    return h_('img', imgObj);
};

/**
 * Helper: Render video element
 */
export const _renderVideo = (h_, src, classOrOptionsObj = {}) => {
    return h_('video', {
        attrs: {
            title: src,
            src,
            controls: true,
            frameborder: '0',
            allow: 'autoplay; encrypted-media',
            allowfullscreen: true,
            allow: 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share',
            referrerpolicy: 'strict-origin-when-cross-origin',
        },
        class: 'container',
        ref: 'rawHtml',
        ...classOrOptionsObj,
    });
};

/**
 * Helper: Render audio element
 */
export const _renderAudio = (h_, src, classOrOptionsObj = {}) => {
    return h_('audio', {
        attrs: {
            title: src,
            src,
            controls: true,
            autoplay: false,
        },
        class: 'container',
        style: {
            height: 'revert',
            width: 'revert',
        },
        ref: 'rawHtml',
        ...classOrOptionsObj,
    });
};

/**
 * Helper: Render YouTube iframe
 */
export const _renderYouTube = (h_, src, classOrOptionsObj = {}) => {
    const embedSrc = src
        .replace('.com/', '.com/embed/')
        .replace('.be/', 'be.com/embed/');
    return h_('iframe', {
        class: 'video-stream html5-main-video container',
        attrs: {
            title: src,
            src: embedSrc,
            controls: true,
            frameborder: '0',
            allow: 'autoplay; encrypted-media',
            allowfullscreen: true,
            allow: 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share',
            referrerpolicy: 'strict-origin-when-cross-origin',
        },
        ref: 'rawHtml',
        ...classOrOptionsObj,
    });
};

/**
 * WBC Logic Helpers — Pure functions (no `this` dependency)
 */

export function _stripScope(opts) {
    if (!opts || typeof opts !== 'object') return opts;
    const { scope, comp, ...rest } = opts;
    return rest;
}

export function _tagHasOptions(tagStr) {
    if (typeof tagStr !== 'string') return false;
    const inner = tagStr.replace(/^</, '').replace(/>$/, '');
    return inner.includes(',');
}

export function _tagStrToWBC(tagStr) {
    if (typeof tagStr !== 'string' || !tagStr.startsWith('<') || !tagStr.endsWith('>')) return null;
    const inner = tagStr.slice(1, -1);
    const parts = inner.split(',').map(s => s.trim());
    const tag = parts[0].replace('~', '');
    const cls = parts[1] || '';
    const link = parts[2] || '';
    const options = {};
    if (cls) options.class = cls;
    if (link) options.to = link;
    return { comp: tag, options, __tilde: parts[0].includes('~') };
}

export function _wbcObjToTagStr(obj) {
    if (!obj || typeof obj !== 'object' || typeof obj.comp !== 'string') return null;
    const opts = obj.options || {};
    const unsupportedKeys = Object.keys(opts).filter(k => !['class', 'to'].includes(k));
    if (unsupportedKeys.length) return null;
    const cls = typeof opts.class === 'string' ? opts.class : '';
    const link = typeof opts.to === 'string' ? opts.to : '';
    const parts = [obj.comp];
    if (cls || link) parts.push(cls);
    if (link) parts.push(link);
    return `<${parts.join(',')}>`;
}

/**
 * Merge a tag string with additional options.
 * Pure function — no `this` needed.
 */
export function _mergeTagWithOptions(tagStr, opts, replace) {
    const base = _tagStrToWBC(tagStr);
    if (!base) return tagStr;
    const incomingClass = typeof opts?.class === 'string' ? opts.class : '';
    const existingClass = base.options.class || '';
    const mergedClass = replace
        ? (incomingClass || existingClass)
        : [existingClass, incomingClass].filter(Boolean).join(' ');
    const merged = {
        comp: (base.__tilde ? '~' : '') + base.comp,
        options: {
            ...(replace ? {} : base.options),
            ...opts,
            ...(mergedClass ? { class: mergedClass } : {}),
        }
    };
    delete merged.options.scope;
    return merged;
}

/**
 * Extract the component name from a descriptor, stripping ~, *, <, > markers.
 * Pure function — no `this` needed.
 */
export function comp(el) {
    let theComp =
        el?.switch === true ? el?.hComp || el?.comp : el?.comp || el?.hComp;
    if (typeof theComp == "string") {
        return theComp
            .replace("~", "")
            .replace("*", "")
            .replace("<", "")
            .replace(">", "");
    }
    return theComp;
}

/* ================================================================
 * Formerly `this`-dependent methods — now pure with explicit `ctx` param
 * ================================================================ */

/**
 * Resolve component options, applying rules, menu state, and switch behavior.
 * Pure function: receives component instance via `ctx` parameter.
 *
 * @param {Object} el    - The element descriptor
 * @param {Object} [ctx] - Vue component instance (or object with menu, validators,
 *                         lang, itemListeners, objLang). Falls back to `this`.
 * @returns {Object} Resolved options object
 */
export function _wbcOptions(el, ctx) {
    const s = ctx || this;

    let theOpts =
        el?.switch === true
            ? el?.hOptions || el?.options
            : el?.options || el?.hOptions;

    if (!theOpts) {
        return el;
    }

    theOpts = {
        ...theOpts,
        ...(s.menu
            ? theOpts?.menu?.activeOptions
            : theOpts?.menu?.active
                ? theOpts?.menu?.activeRootOptions
                : {}),
    };

    let rules = [];
    if (Array.isArray(theOpts?.rules)) {
        rules = (theOpts?.rules || []).map((key) => {
            if (s.validators?.[key]) {
                return (v) => s.validators[key](v, { lg: s.lang });
            } else {
                return key;
            }
        });
    } else if (typeof theOpts?.rules == "object") {
        rules = Object.entries(theOpts?.rules).map(([key, val]) => {
            if (s.validators?.[key] && typeof val == "function") {
                return val;
            } else if (s.validators?.[key] && typeof val == "object") {
                return (v) => s.validators[key](v, val);
            } else {
                return (v) =>
                    s.validators[key](v, { lg: s.lang, message: val });
            }
        });
    }

    if (typeof theOpts !== 'object' || theOpts === null) {
        return s.objLang(theOpts, s.lang);
    }

    if (!theOpts.props) {
        theOpts.props = {};
    }

    if (rules.length >= 1) {
        theOpts.props.rules = rules;
    }

    if (typeof el?.switch == "boolean") {
        s.itemListeners[el?.switchEvent || "mouseenter"] = (event) => {
            el.switch = !el.switch;
        };
    } else if (el instanceof Object) {
        el.options = el[el?.switch || "options"];
    }

    return s.objLang(theOpts, s.lang);
}

/**
 * Render a global header VNode from an element descriptor.
 * Pure function: receives computedKey via `ctx` parameter.
 */
export function globalHeaderVN(el, h_, ctx) {
    const s = ctx || this;
    let header =
        el?.switch === true
            ? el?.hHeader || el?.header
            : el?.header || el?.hHeader;

    if (!header) return null;
    return h_("WBC", {
        keyy: `wbc-key-header-${s.computedKey}`,
        props: { item: header },
    });
}

/**
 * Render a global footer VNode from an element descriptor.
 * Pure function: receives computedKey via `ctx` parameter.
 */
export function globalFooterVN(el, h_, ctx) {
    const s = ctx || this;
    let footer =
        el?.switch === true
            ? el?.hFooter || el?.footer
            : el?.footer || el?.hFooter;
    if (!footer) return null;
    return h_("WBC", {
        keyy: `wbc-key-footer-${s.computedKey}`,
        props: { item: footer },
    });
}

/**
 * Render inside header VNodes from an element's options.
 * Pure function: receives toWBC_ via `ctx` parameter.
 */
export function insideHeadersVN(el, h_, ctx) {
    const s = ctx || this;
    let headers =
        el?.switch === true
            ? el?.hOptions?.headers || el?.options?.headers
            : el?.options?.headers || el?.hOptions?.headers;
    if (!headers) return null;
    return s.toWBC_(headers, h_);
}

/**
 * Render inside footer VNodes from an element's options.
 * Pure function: receives toWBC_ via `ctx` parameter.
 */
export function insideFootersVN(el, h_, ctx) {
    const s = ctx || this;
    let footers =
        el?.switch === true
            ? el?.hOptions?.footers || el?.options?.footers
            : el?.options?.footers || el?.hOptions?.footers;
    if (!footers) return null;
    return s.toWBC_(footers, h_);
}

/**
 * Extract HTML content from an element descriptor.
 * Pure function: receives isPlainObject via `ctx` parameter.
 */
export function html(el, ctx) {
    const s = ctx || this;
    if (!s.isPlainObject(el)) {
        return el;
    }
    return el?.switch === true
        ? el?.hOptions?.html || el?.options?.html
        : el?.options?.html || el?.hOptions?.html;
}
