/**
 * utils/aesCrypto.js
 * AES encryption/decryption wrappers that depend on Vue.CryptoJS.
 * Extracted from WBC.js as part of the WBC.js decomposition (task 2.2).
 *
 * The actual crypto operations delegate to the pure functions in
 * pro/utils_pro.js (which take CryptoJS as an explicit 4th argument).
 * These wrappers handle the Vue.CryptoJS availability check.
 */

import { aesEnc as aesEncPure, aesDec as aesDecPure } from '../pro/utils_pro.js';

/**
 * Encrypt plaintext using AES-CBC.  Requires vue-cryptojs to be installed.
 * @param {string} plaintext - Text to encrypt.
 * @param {string} key - AES key (UTF-8).
 * @param {string} iv - Initialization vector (UTF-8).
 * @returns {string} Ciphertext hex string, or empty string if CryptoJS is unavailable.
 */
export function aesEnc(plaintext, key, iv) {
    const CryptoJS = typeof Vue !== 'undefined' && Vue.CryptoJS ? Vue.CryptoJS : null;
    if (!CryptoJS) {
        console.warn('[WBC] vue-cryptojs is not installed \u2014 aesEnc unavailable');
        return '';
    }
    return aesEncPure(plaintext, key, iv, CryptoJS);
}

/**
 * Decrypt AES-CBC ciphertext.  Requires vue-cryptojs to be installed.
 * @param {string} ciphertext - Ciphertext hex string to decrypt.
 * @param {string} key - AES key (UTF-8).
 * @param {string} iv - Initialization vector (UTF-8).
 * @returns {string} Decrypted plaintext, or empty string if CryptoJS is unavailable.
 */
export function aesDec(ciphertext, key, iv) {
    const CryptoJS = typeof Vue !== 'undefined' && Vue.CryptoJS ? Vue.CryptoJS : null;
    if (!CryptoJS) {
        console.warn('[WBC] vue-cryptojs is not installed \u2014 aesDec unavailable');
        return '';
    }
    return aesDecPure(ciphertext, key, iv, CryptoJS);
}