/**
 * utils/security.js
 * Code execution isolation, safe evaluation, and script sanitization
 */
import * as acorn from 'acorn';
import * as walk from 'acorn-walk';

const BLOCKED_PROPS = ['constructor', '__proto__', 'prototype', 'getPrototypeOf', 'setPrototypeOf', 'callee'];
const BLOCKED_GLOBALS = ['globalThis', 'eval', 'Function', 'window', 'document', 'process', 'Reflect', 'Object', 'Array', 'this', 'arguments', 'callee'];

// ─── Trusted-authoring vs untrusted-content gate ───
// WBC `[[ ... ]]` blocks authored by the developer are *trusted* code: they rely
// on real closures, `this`, `console`, `alert`, and context mutation to wire up
// component events/actions. The acorn AST sandbox below intentionally blocks all
// of that — correct for rendering *untrusted* third-party content, but it silently
// breaks the author's own interactive blocks (dead events, malformed renders).
//
// So we gate: in owner/developer (trusted) mode we evaluate with the legacy
// `new Function` engine (full power, byte-for-byte the historical behavior);
// otherwise we fall through to the hardened AST interpreter. Mirrors the
// `__WBC_DEV__` 3-mode pattern used across WBC.js / WBC.lifecycle.js / store.
//   serve_vite        → __WBC_DEV__=true  → legacy eval (authoring)
//   serve_vite:pro    → __WBC_DEV__=false → AST sandbox (simulated prod user)
//
// Secure-by-default: the legacy full-power path is taken ONLY when one of the
// trust flags is explicitly true (the vite apps define them). When both are absent
// — bundlers that don't define them, unit tests, or any unknown host — we keep the
// hardened AST sandbox so untrusted contexts never get eval-grade power by accident.
//
// Two independent opt-ins, because authoring-trust and the free/pro feature tier are
// different concerns:
//   __WBC_DEV__              → owner/developer build (also unlocks dev-only features).
//   __WBC_TRUSTED_CONTENT__  → "every WBC block in this host is authored by us, so
//                              run it full-power regardless of the simulated tier."
//                              Set by first-party apps (e.g. the docs/demo site) so
//                              their live demos stay interactive in free/pro builds
//                              WITHOUT leaking dev-only features. Third-party embedders
//                              never set it, so they stay sandboxed.
const __WBC_TRUSTED_EVAL__ =
    (typeof __WBC_DEV__ !== 'undefined' && __WBC_DEV__ === true) ||
    (typeof __WBC_TRUSTED_CONTENT__ !== 'undefined' && __WBC_TRUSTED_CONTENT__ === true);

/**
 * Legacy `new Function` evaluator — the historical WBC behavior.
 * Used only on the trusted-authoring path (see `__DEV__` gate in `safeEval`).
 * Masks the obvious ambient I/O globals but otherwise runs code as real JS so
 * that event handlers (`on:{click: that => () => {...}}`), `this`, `console`,
 * and context mutation all work exactly as authors expect.
 */
function legacyEval(code, context = {}, quiet = false) {
    if (typeof code !== 'string' || !code.trim()) return code;

    const masks = {
        window: null,
        document: null,
        fetch: null,
        localStorage: null,
        sessionStorage: null,
        process: null,
        global: null,
        XMLHttpRequest: null,
    };

    const combinedContext = { ...masks, ...context };
    const keys = Object.keys(combinedContext);
    const vals = Object.values(combinedContext);

    try {
        const trimmed = code.trim();
        // Code that is already a function definition (arrow / function / paren-wrapped)
        if (trimmed.startsWith('(') || trimmed.startsWith('function') || trimmed.includes('=>')) {
            const fnWrapper = new Function(...keys, `"use strict"; return (${code});`);
            const evaluatedFn = fnWrapper(...vals);
            if (typeof evaluatedFn === 'function') {
                return evaluatedFn(context);
            }
        }

        // Bare expression literals (array, object, template/string literal) must be
        // evaluated as an EXPRESSION, not a statement. Without this, `[...]` is a valid
        // statement that runs and yields nothing, so the IIFE wrapper below returns
        // undefined and the array is lost. (Objects only "worked" by accident: `{...}`
        // is a syntax error as a block statement, so it threw and hit the expression
        // fallback in catch — arrays don't throw, so they never reached it.)
        if (
            trimmed.startsWith('[') ||
            trimmed.startsWith('{') ||
            trimmed.startsWith('`') ||
            trimmed.startsWith("'") ||
            trimmed.startsWith('"')
        ) {
            const fnExpr = new Function(...keys, `"use strict"; return (${code});`);
            return fnExpr(...vals);
        }

        // Otherwise wrap in a self-executing block to allow statements
        const fn = new Function(...keys, `"use strict"; return (function(){ ${code} })();`);
        return fn(...vals);
    } catch (e) {
        // Final fallback for raw expressions (e.g. bare object literals)
        try {
            const fnExpr = new Function(...keys, `"use strict"; return (${code});`);
            return fnExpr(...vals);
        } catch (e2) {
            if (!quiet) {
                console.error("[WBC-UI SafeEval Error]", e2, "Code:", code);
            }
            return undefined;
        }
    }
}

/**
 * AST-walking sandboxed interpreter.
 * Evaluates a parsed acorn AST node in a restricted context.
 * No eval(), no new Function() — pure AST interpretation.
 */
function interpretAST(node, sb) {
    if (node == null) return undefined;

    switch (node.type) {
        case 'Program':
            return interpretProgram(node, sb);

        case 'ExpressionStatement':
            return interpretAST(node.expression, sb);

        case 'BlockStatement':
            return interpretBlock(node, sb);

        case 'ReturnStatement':
            return node.argument ? interpretAST(node.argument, sb) : undefined;

        case 'Literal':
            return node.value;

        case 'Identifier':
            return sb[node.name];

        case 'ObjectExpression': {
            const obj = {};
            for (const prop of node.properties) {
                const key = prop.computed
                    ? interpretAST(prop.key, sb)
                    : (prop.key.type === 'Identifier' ? prop.key.name : prop.key.value);
                const val = interpretAST(prop.value, sb);
                obj[key] = val;
            }
            return obj;
        }

        case 'ArrayExpression':
            return node.elements.map(e => e ? interpretAST(e, sb) : undefined);

        case 'MemberExpression': {
            const obj = interpretAST(node.object, sb);
            const key = node.computed
                ? interpretAST(node.property, sb)
                : (node.property.type === 'Identifier' ? node.property.name : node.property.value);
            if (obj == null) return undefined;
            return obj[key];
        }

        case 'CallExpression': {
            const callee = interpretAST(node.callee, sb);
            if (typeof callee !== 'function') return undefined;
            const args = node.arguments.map(a => interpretAST(a, sb));
            return callee(...args);
        }

        case 'ArrowFunctionExpression':
            return createSandboxArrow(node, sb);

        case 'FunctionExpression':
            return createSandboxFunction(node, sb);

        case 'BinaryExpression':
            return interpretBinary(node, sb);

        case 'LogicalExpression':
            return interpretLogical(node, sb);

        case 'UnaryExpression':
            return interpretUnary(node, sb);

        case 'ConditionalExpression':
            return interpretAST(node.test, sb)
                ? interpretAST(node.consequent, sb)
                : interpretAST(node.alternate, sb);

        case 'TemplateLiteral': {
            let str = '';
            for (let i = 0; i < node.quasis.length; i++) {
                str += node.quasis[i].value.cooked;
                if (i < node.expressions.length) {
                    str += String(interpretAST(node.expressions[i], sb));
                }
            }
            return str;
        }

        case 'SequenceExpression':
            return node.expressions.reduce((_, e) => interpretAST(e, sb), undefined);

        case 'AssignmentExpression':
            return interpretAssignment(node, sb);

        case 'UpdateExpression':
            return interpretUpdate(node, sb);

        case 'ThisExpression':
            return undefined;

        case 'NewExpression':
            throw new Error('Blocked: unsafe code pattern');

        case 'VariableDeclaration':
            return undefined;

        default:
            throw new Error(`[SafeEval] Unsupported AST node: ${node.type}`);
    }
}

function interpretProgram(node, sb) {
    let result;
    for (const stmt of node.body) {
        result = interpretAST(stmt, sb);
    }
    return result;
}

function interpretBlock(node, sb) {
    let result;
    for (const stmt of node.body) {
        result = interpretAST(stmt, sb);
    }
    return result;
}

function createSandboxArrow(node, sb) {
    const params = node.params.map(p => {
        if (p.type === 'Identifier') return p.name;
        if (p.type === 'RestElement') return p.argument.name;
        return null;
    }).filter(Boolean);

    return (...args) => {
        const fnSb = Object.create(sb);
        params.forEach((name, i) => { fnSb[name] = args[i]; });
        fnSb.__proto__ = undefined;
        if (node.body.type === 'BlockStatement') {
            return interpretBlock(node.body, fnSb);
        }
        return interpretAST(node.body, fnSb);
    };
}

function createSandboxFunction(node, sb) {
    const params = node.params.map(p => {
        if (p.type === 'Identifier') return p.name;
        if (p.type === 'RestElement') return p.argument.name;
        if (p.type === 'AssignmentPattern') return p.left.name;
        return null;
    }).filter(Boolean);

    return function (...args) {
        const fnSb = Object.create(sb);
        params.forEach((name, i) => { fnSb[name] = args[i]; });
        fnSb.__proto__ = undefined;
        return interpretBlock(node.body, fnSb);
    };
}

function interpretBinary(node, sb) {
    const left = interpretAST(node.left, sb);
    const right = interpretAST(node.right, sb);
    switch (node.operator) {
        case '+': return left + right;
        case '-': return left - right;
        case '*': return left * right;
        case '/': return left / right;
        case '%': return left % right;
        case '**': return left ** right;
        case '==': return left == right;
        case '!=': return left != right;
        case '===': return left === right;
        case '!==': return left !== right;
        case '<': return left < right;
        case '>': return left > right;
        case '<=': return left <= right;
        case '>=': return left >= right;
        case '<<': return left << right;
        case '>>': return left >> right;
        case '>>>': return left >>> right;
        case '&': return left & right;
        case '|': return left | right;
        case '^': return left ^ right;
        case 'in': return left in right;
        case 'instanceof': return left instanceof right;
        default: return undefined;
    }
}

function interpretLogical(node, sb) {
    const left = interpretAST(node.left, sb);
    if (node.operator === '&&') return left && interpretAST(node.right, sb);
    if (node.operator === '||') return left || interpretAST(node.right, sb);
    if (node.operator === '??') return left != null ? left : interpretAST(node.right, sb);
    return undefined;
}

function interpretUnary(node, sb) {
    const arg = interpretAST(node.argument, sb);
    switch (node.operator) {
        case '-': return -arg;
        case '+': return +arg;
        case '!': return !arg;
        case '~': return ~arg;
        case 'typeof': return typeof arg;
        case 'void': return void arg;
        case 'delete': return true;
        default: return undefined;
    }
}

function interpretAssignment(node, sb) {
    const value = interpretAST(node.right, sb);
    if (node.left.type === 'Identifier') {
        sb[node.left.name] = value;
    } else if (node.left.type === 'MemberExpression') {
        const obj = interpretAST(node.left.object, sb);
        const key = node.left.computed
            ? interpretAST(node.left.property, sb)
            : node.left.property.name;
        if (obj != null) obj[key] = value;
    }
    switch (node.operator) {
        case '=': return value;
        case '+=': return (sb[node.left.name] = (sb[node.left.name] || 0) + value);
        case '-=': return (sb[node.left.name] = (sb[node.left.name] || 0) - value);
        case '*=': return (sb[node.left.name] = (sb[node.left.name] || 0) * value);
        default: return value;
    }
}

function interpretUpdate(node, sb) {
    const ident = node.argument.name;
    const old = sb[ident] || 0;
    if (node.operator === '++') sb[ident] = old + 1;
    if (node.operator === '--') sb[ident] = old - 1;
    return node.prefix ? sb[ident] : old;
}

function buildSandbox(context) {
    const masks = {
        window: undefined, document: undefined, fetch: undefined,
        localStorage: undefined, sessionStorage: undefined,
        process: undefined, global: undefined, XMLHttpRequest: undefined,
        globalThis: undefined, eval: undefined, Function: undefined,
        Reflect: undefined, Object: undefined, Array: undefined,
        setTimeout: undefined, setInterval: undefined,
        console: undefined, location: undefined, navigator: undefined
    };
    const sb = Object.assign(Object.create(null), masks, context);
    sb.__proto__ = undefined;
    return sb;
}

/**
 * Deep-freeze an object to prevent mutation.
 */
const deepFreeze = (obj, seen = new WeakSet()) => {
    if (obj && typeof obj === 'object' && !Object.isFrozen(obj)) {
        if (seen.has(obj)) return obj;
        seen.add(obj);
        if (obj._isVue || obj instanceof Element) return obj;
        Object.freeze(obj);
        Object.getOwnPropertyNames(obj).forEach(prop => deepFreeze(obj[prop], seen));
    }
    return obj;
};

/**
 * Safely evaluates a string as JavaScript code within a sandboxed interpreter.
 * Uses AST-walking instead of new Function() — no eval at runtime.
 *
 * @param {object} [opts] - Per-call overrides.
 * @param {boolean} [opts.trusted] - Explicitly force the evaluator path, overriding the
 *   compile-time `__WBC_TRUSTED_EVAL__` default. `true` → legacy full-power eval;
 *   `false` → hardened AST sandbox (use this for UNTRUSTED content — e.g. WBC descriptors
 *   decompressed from a URL — so embedded handler strings can never run as real closures,
 *   even in a build where `__WBC_TRUSTED_CONTENT__` makes authored content eval full-power).
 *   When omitted, the compile-time default applies (unchanged behavior).
 */
export function safeEval(code, context = {}, quiet = false, opts = {}) {
    if (typeof code !== 'string' || !code.trim()) return code;

    // Trust resolution: an explicit per-call `trusted` wins over the compile-time default.
    // This is the trust BOUNDARY between author-written blocks (trusted) and content that
    // entered at runtime from an untrusted source (e.g. the url playground → trusted:false).
    const trusted = opts.trusted === true ? true
        : opts.trusted === false ? false
            : __WBC_TRUSTED_EVAL__;

    // Trusted-authoring path: run the developer's own WBC blocks with the legacy
    // full-power evaluator so events/actions/this/console/mutation behave as before.
    // Untrusted path falls through to the hardened AST interpreter below.
    if (trusted) {
        return legacyEval(code, context, quiet);
    }

    const trimmed = code.trim();
    let ast;

    try {
        ast = acorn.parse(trimmed, { ecmaVersion: 2020 });
    } catch {
        try {
            ast = acorn.parse(`(${trimmed})`, { ecmaVersion: 2020 });
        } catch {
            if (!quiet) console.error("[SafeEval Parse Error]", code);
            return undefined;
        }
    }

    let isSafe = true;

    walk.simple(ast, {
        Identifier(node) { if (BLOCKED_GLOBALS.includes(node.name)) isSafe = false; },
        Literal(node) { if (typeof node.value === 'string' && BLOCKED_PROPS.includes(node.value)) isSafe = false; },
        MemberExpression(node) {
            if (!node.computed && node.property.type === 'Identifier') { if (BLOCKED_PROPS.includes(node.property.name)) isSafe = false; }
            if (node.computed && node.property.type !== 'Literal') isSafe = false;
            if (node.computed && node.property.type === 'Literal' && typeof node.property.value === 'string') { if (BLOCKED_PROPS.includes(node.property.value)) isSafe = false; }
        },
        CallExpression(node) { if (node.callee.type === 'Identifier' && BLOCKED_GLOBALS.includes(node.callee.name)) isSafe = false; },
        NewExpression(node) { if (node.callee.type === 'Identifier' && BLOCKED_GLOBALS.includes(node.callee.name)) isSafe = false; },
        ThisExpression() { isSafe = false; }
    });

    if (!isSafe) {
        if (!quiet) console.error("[SafeEval Error] Blocked by AST Validator.");
        throw new Error('Blocked: unsafe code pattern');
    }

    // Freeze context objects for defense in depth (prevents mutation)
    Object.keys(context).forEach(k => {
        if (typeof context[k] === 'object' && context[k] !== null) deepFreeze(context[k]);
    });

    const sandbox = buildSandbox(context);

    try {
        const result = interpretAST(ast, sandbox);
        // If the code evaluates to a function and there's a non-empty context,
        // call the function with the context (matching the legacy behavior for
        // arrow/function expressions passed via context)
        if (typeof result === 'function' && context && Object.keys(context).length > 0) {
            return result(context);
        }
        return result;
    } catch (e) {
        if (!quiet) console.error("[SafeEval] Interpreter Error", code, e);
        return undefined;
    }
}

/**
 * Transforms a string potentially containing JS into an object.
 *
 * @param {object} [opts] - Forwarded to {@link safeEval}; pass `{ trusted: false }` to
 *   evaluate UNTRUSTED input (e.g. a url-supplied descriptor) in the hardened AST sandbox.
 */
export function strToObj(input, opts = {}) {
    if (typeof input !== "string") return input;
    try { return JSON.parse(input); }
    catch {
        // Only eval if it looks like actual code structure
        // Require: function calls (), object/array literals {}, [], or operators
        // Single identifiers like "r", "red" should NOT be evaled - they're just strings
        const hasCodeStructure = /[\(\)\{\}\[]/.test(input) ||  // parens/braces/brackets
                                /[\+\-\*\/\%\?\:]/.test(input);   // operators
        if (!hasCodeStructure) return input;
        const res = safeEval(input, {}, true, opts);
        // Fall back to the literal string when evaluation produced no meaningful value.
        // A hyphenated label like "WBC-dynamic-Routing" trips the operator heuristic above
        // and parses as `WBC - dynamic - Routing`; the legacy evaluator throws on the unknown
        // identifiers (→ undefined → fallback), but the AST sandbox reads them as undefined and
        // yields NaN. Treat NaN like undefined so both paths return the original text.
        if (res === undefined || (typeof res === 'number' && Number.isNaN(res))) return input;
        return res;
    }
}
