/**
 * Decorator: Apply RTL (Right-to-Left) direction if Arabic
 */
export function applyRTL(self, h, finalRender) {
    if (self.lang == "ar") {
        return h(
            "span",
            { style: { direction: "rtl", textAlign: "right" } },
            Array.isArray(finalRender) && finalRender.length > 0
                ? finalRender
                : [finalRender]
        );
    }
    return finalRender;
}
